import React, {useEffect, useState} from 'react';
import { Helmet } from 'react-helmet';
import {Redirect} from "react-router";
import { connect } from 'react-redux';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import {ConfigProvider, Layout} from 'antd';

import {
  getAntLocale,
  getDateLocale,
  DateFnsLocaleContext
} from './locale';
import {hasError, hubService} from './hub';
import {faviconUrl} from './env';
import './App.less';

import SetupWizard from './components/pages/setup/SetupWizard';
import DevicesPage from './components/pages/DevicesPage';
import HubHeader from "./components/core/HubHeader";
import NotFoundPage from "./components/pages/NotFoundPage";
import SettingsContainer from "./components/pages/settings/SettingsContainer";
import LogViewPage from "./components/pages/logview/LogViewPage";
import {State} from "./store/state";

const {Content} = Layout;

const App = connect<State, any, any, State>(({language}) => ({language}))((props) => {
  const { language } = props;
  const [setupComplete, setSetupComplete] = useState(true);
  useEffect(() => {
    hubService.isSetupComplete().then(rsp => {
      if (hasError(rsp)) {
        console.error('Error on setup state check: %s', rsp.error?.message);
        return;
      }
      setSetupComplete(!!rsp.result?.isComplete);
    }).catch(err => console.error('Failed to check setup state: %s', err))
  }, []);

  return (
    <Router>
      <Helmet>
        <link rel="icon" href={faviconUrl} />
      </Helmet>
      <Layout className="App layout" style={{minHeight: '100vh'}}>
        <HubHeader showMenu={setupComplete}/>
        <Content style={{padding: '0 0'}} className="container App__container">
          <DateFnsLocaleContext.Provider value={getDateLocale(language)}>
            <ConfigProvider locale={getAntLocale(language)}>
              <Switch>
                <Route exact path="/" component={DevicesPage}/>
                <Route path="/setup" component={SetupWizard}/>
                <Route path="/settings" component={SettingsContainer} />
                <Route path="/events" component={LogViewPage} />
                <Route component={NotFoundPage} />
              </Switch>
              {!setupComplete ? <Redirect to='/setup' /> : null }
            </ConfigProvider>
          </DateFnsLocaleContext.Provider>
        </Content>
      </Layout>
    </Router>
  );
});

export default App;
