import React, { useEffect, useRef, useState } from 'react';
import { useTranslation } from "react-i18next";
import { TFunction } from "i18next";
import AbortController from "abort-controller";
import { Button, Modal, Result, Space, Steps, Typography } from 'antd';
import DeviceAddressList from '../lists/DeviceAddressList';
import { useLoadState } from "../../util/hooks";
import { DeviceScanInfo, devicesService, hubService } from "../../hub";
import { ScanError } from "../../hub/requests";
import { ScanTarget } from "../../hub/scan-target";
import {
  scanInfoToRegistrations,
  scanTargetsToScanRequest,
  shouldOmitDevice
} from "../../types/devices";
import FarmHashInput, { DEFAULT_FARM_HASH_EVENT, FarmHashInputEvent } from "../form/FarmHashInput";
import ScanResultsList from "../lists/ScanResultsList";
import FileOpenButton from "../form/FileOpenButton";
import {
  filterUniqueTargets,
  scanTargetsFromFile
} from "../../util/scan-targets";
import UnknownDevicesNotification from "../misc/scan/UnknownDevicesNotification";
import UnknownDevicesModal from "../misc/scan/UnknownDevicesModal";
import UpdatedDevicesNotification from "../misc/scan/UpdatedDevicesNotification";
import UpdatedDevicesModal from "../misc/scan/UpdatedDevicesModal";

const { Step } = Steps;

interface Props {
  visible: boolean
  onSuccess: (count: number) => void
  onCancel: () => void
}

enum Stage {
  AddressesInput,
  SelectDevices,
  Finish
}

const showScanErrorsModal = (t: TFunction, errs: ScanError[]) => {
  Modal.warn({
    width: 600,
    title: t('scanner.probeErrorTitle'),
    content: <Space direction="vertical">
      <p>
        {t('scanner.probeErrorMessage')}
      </p>
      <ul>
        {errs.map(err => <li>{err.ip} - {err.error}</li>)}
      </ul>
    </Space>
  })
}

const showExistingItemsModal = (t: TFunction, items: DeviceScanInfo[], onOk: () => void) => (
  Modal.warning({
    onOk,
    title: t('scanner.existingItemsErrorTitle'),
    width: 580,
    content: <>
      <Typography.Text>
        {t('scanner.existingItemsErrorMessage', { count: items.length })}
      </Typography.Text>
      <ScanResultsList devices={items} readonly />
    </>
  })
)

interface unknownDevicesState {
  showModal?: boolean
  unknownDevices?: string[]
}

interface updatedDevicesState {
  showModal?: boolean
  updatedDevices?: string[]
}
interface HTMLElementWithController extends HTMLElement {
  controller: AbortController;
}

const unknownDevicesInfoInitialState = {};
const updatedDevicesInfoInitialState = {};
const DeviceAddModal: React.FC<Props> = ({ visible, onSuccess, onCancel }) => {
  const { t } = useTranslation('devicesPage');
  const [loadState, setError, setLoading] = useLoadState(false);
  const [farmHash, setFarmHash] = useState<FarmHashInputEvent>(DEFAULT_FARM_HASH_EVENT);
  const [targets, setTargets] = useState<ScanTarget[]>([]);
  const [stage, setStage] = useState<Stage>(Stage.AddressesInput);
  const [devices, setDevices] = useState<DeviceScanInfo[]>([]);
  const [selectedDeviceKeys, setSelectedDeviceKeys] = useState<number[]>([]);
  const [valid, setValid] = useState(false);
  const [unknownDevicesInfo, setUnknownDevicesInfo] = useState<unknownDevicesState>(unknownDevicesInfoInitialState);
  const [updatedDevicesInfo, setUpdatedDevicesInfo] = useState<updatedDevicesState>(updatedDevicesInfoInitialState);
  const [isDisabledCancelButton, setDisableCancelButton] = useState(false);
  const cancelButton = useRef<HTMLElementWithController>(null);

  const controller = new AbortController();

  const close = (cancel = true, count = devices.length) => {
    setStage(Stage.AddressesInput);
    setFarmHash(DEFAULT_FARM_HASH_EVENT);
    setTargets([]);
    setValid(false);
    setError(null);
    setUnknownDevicesInfo(unknownDevicesInfoInitialState);
    setUpdatedDevicesInfo(updatedDevicesInfoInitialState);
    setSelectedDeviceKeys([]);
    cancel ? onCancel() : onSuccess(count);
  }

  useEffect(() => {
    // check validation state on farm selection
    setValid(selectedDeviceKeys.length > 0 && farmHash.valid);
  }, [selectedDeviceKeys, farmHash, setValid]);

  useEffect(() => {
    // check targets list validation
    setValid(targets.length > 0);
  }, [targets, setValid]);

  const getDevices = () => {
    setLoading(true);
    setDisableCancelButton(false);
    // TODO: implement chunk scan
    const req = scanTargetsToScanRequest(targets);
    setUnknownDevicesInfo(unknownDevicesInfoInitialState);
    setUpdatedDevicesInfo(updatedDevicesInfoInitialState);
    const { signal } = controller;
    attachControllerToElem();

    hubService.scan({ ...req, signal })
      .then(rsp => {
        if (rsp.errors) {
          showScanErrorsModal(t, rsp.errors);
        }

        const { devices, unknownDevices, updatedDevices } = rsp;
        const keys = devices
          .map((d, i) => {
            const { hasHiveOS, exists } = d;
            return { hasHiveOS, exists, i };
          })
          .filter(d => !shouldOmitDevice(d))
          .map((d) => d.i);
        setUnknownDevicesInfo({ unknownDevices });
        setUpdatedDevicesInfo({ updatedDevices });
        setDevices(devices);
        setSelectedDeviceKeys(keys);
        setLoading(false);
        setError(null);
        if (updatedDevices?.length) {
          hubService.restartMonitor()
            .catch(err => setError(err.message));
        }
      })
      .catch(err => setError(err.message))
      .finally(() => setDisableCancelButton(true));
  };

  const attachControllerToElem = () => {
    if (cancelButton.current === null) return;
    cancelButton.current.controller = controller;
  };

  const abortRequest = () => {
    if (cancelButton.current === null) return;
    cancelButton.current.controller.abort()
  };

  const getCurrentStep = () => {
    switch (stage) {
      case Stage.AddressesInput:
        return <DeviceAddressList
          values={targets}
          onChange={setTargets}
        />
      case Stage.SelectDevices:
        return <Space direction="vertical" style={{ width: '100%' }}>
          <FarmHashInput
            disabled={loadState.loading}
            value={farmHash.value}
            onChange={setFarmHash}
            placeholder={t('scanner.farmHashPlaceholder')}
          />
          <UnknownDevicesNotification
            visible={!!unknownDevicesInfo.unknownDevices?.length}
            itemsCount={unknownDevicesInfo.unknownDevices?.length}
            onAction={() => setUnknownDevicesInfo({ ...unknownDevicesInfo, showModal: true })}
          />
          <UpdatedDevicesNotification
            visible={!!updatedDevicesInfo.updatedDevices?.length}
            itemsCount={updatedDevicesInfo.updatedDevices?.length}
            onAction={() => setUpdatedDevicesInfo({ ...updatedDevicesInfo, showModal: true })}
          />
          <ScanResultsList
            isLoading={loadState.loading}
            devices={devices}
            selectedKeys={selectedDeviceKeys}
            onSelectionChange={setSelectedDeviceKeys}
          />
        </Space>
      case Stage.Finish:
        return <Result
          status="success"
          title="Success"
          subTitle={t('scanner.addSuccess')}
          extra={[
            <Button type="primary" key="end" onClick={() => close(false)}>
              {t('actions.close')}
            </Button>
          ]}
        />
      default:
        return '???'
    }
  }

  const registerDevices = () => {
    setLoading(true);
    const selectedDevices = selectedDeviceKeys.map(i => devices[i]);
    const registrations = scanInfoToRegistrations(farmHash.value, selectedDevices);
    devicesService.addDevices(registrations, false)
      .then(rsp => {
        const { duplicates } = rsp;
        if (!duplicates?.length) {
          close(false, selectedDevices.length);
          return;
        }

        // AHUB-67: show duplicates list.
        //
        // Report close event as canceled, if all items are duplicated.
        const existingIps = new Set(duplicates);
        const existingDevices = devices.filter(d => existingIps.has(d.ip));
        const addedCount = selectedDevices.length - duplicates.length;
        showExistingItemsModal(
          t, existingDevices,
          () => close(addedCount === 0, addedCount)
        );
      }).catch(err => {
        setStage(Stage.Finish);
        setError(err.message ?? err);
      });
  };

  const nextStep = () => {
    switch (stage) {
      case Stage.AddressesInput:
        getDevices();
        setStage(Stage.SelectDevices);
        return;
      case Stage.SelectDevices:
        registerDevices();
        return;
      default:
        return;
    }
  }

  const back = () => {
    if (stage === Stage.AddressesInput) {
      return;
    }

    setError(null);
    setValid(true);
    setStage(stage - 1);
  }

  const onFileSelect = (list: FileList | null) => {
    if (!list?.length) return;
    setLoading(true);
    const file = list[0]; // array destruct not supported by iterators
    scanTargetsFromFile(file)
      .then(list => {
        if (!list.length) {
          return Promise.reject(t('scanner.csvEmptyError'));
        }

        return list;
      })
      .then(list => filterUniqueTargets(targets.concat(list)))
      .then(newTargets => {
        setLoading(false);
        setTargets(newTargets);
      })
      .catch(err => {
        setLoading(false);
        Modal.error({
          title: t('scanner.csvReadError', file),
          content: err.message ?? err,
        })
      })
  };

  const closable = stage === Stage.Finish || !loadState.loading;

  return <Modal
    visible={visible}
    title={t('scanner.title')}
    centered={true}
    closable={closable}
    maskClosable={closable}
    onCancel={() => close(true)}
    width={840}
    footer={<>
      <FileOpenButton
        style={{ float: 'left' }}
        label={t('scanner.actions.csvImport')}
        disabled={loadState.loading}
        hidden={stage !== Stage.AddressesInput}
        accept="text/csv"
        onChange={onFileSelect}
        type="link"
      />
      <Button
        type="text"
        ref={cancelButton}
        onClick={abortRequest}
        hidden={stage === Stage.AddressesInput}
        disabled={isDisabledCancelButton}
        danger>
        {t('actions.cancel')}
      </Button>

      <Button
        type="text"
        onClick={back}
        disabled={stage === Stage.AddressesInput || loadState.loading}>
        {t('actions.goBack')}
      </Button>
      <Button
        type="primary"
        loading={loadState.loading}
        disabled={loadState.loading || !valid || loadState.error || stage === Stage.Finish}
        onClick={nextStep}>
        {t('actions.next')}
      </Button>
    </>}
  >
    <Steps size="small" current={stage} style={{ marginBottom: 18 }}>
      <Step title={t('scanner.steps.search')} />
      <Step title={t('scanner.steps.selectFarm')} />
      <Step title={t('scanner.steps.finish')} />
    </Steps>
    {loadState.error ?
      <Result
        status="error"
        title={t('labels.errorTitle')}
        subTitle={loadState.error}
      /> :
      getCurrentStep()
    }
    <UnknownDevicesModal
      visible={unknownDevicesInfo.showModal}
      ips={unknownDevicesInfo.unknownDevices}
      onClose={() => {
        setUnknownDevicesInfo({ ...unknownDevicesInfo, showModal: false })
      }
      }
    />
    <UpdatedDevicesModal
      visible={updatedDevicesInfo.showModal}
      ips={updatedDevicesInfo.updatedDevices}
      onClose={() => {
        setUpdatedDevicesInfo({ ...updatedDevicesInfo, showModal: false })
      }
      }
    />
  </Modal>
}

export default DeviceAddModal;
