import React, { useState } from 'react';
import {useTranslation} from "react-i18next";
import {Typography, Button, Space, Result, Row, Col} from 'antd';
import {useLoadState} from "../../../util/hooks";
import FarmHashInput, {DEFAULT_FARM_HASH_EVENT} from "../../form/FarmHashInput";
import {hubService} from "../../../hub";
import HubPage from "../../core/HubPage";

export default function() {
  const { t } = useTranslation('setupWizard');
  const [isFinished, setFinished] = useState(false);
  const [inputState, setInputState] = useState(DEFAULT_FARM_HASH_EVENT);
  const [loadState, setError, setLoading] = useLoadState();
  const {loading, error} = loadState;

  const {value, valid} = inputState;
  const onSubmit = () => {
    setLoading(true);
    hubService.setupHub({hubFarmHash: value})
      .then(() => {
        setLoading(false);
        setFinished(true);
      }).catch(err => setError(err.message ?? err))
  };

  let content: React.ReactNode;
  if (isFinished) {
    content = (
      <Result
        status="success"
        title={t('setupFinishTitle')}
        subTitle={<>
          <Typography.Paragraph>
            {t('setupFinishMessage')}
          </Typography.Paragraph>
        </>}
        extra={[
          // Force page reload to refresh installation status
          <Button type="primary" onClick={() => window.location.href = '/'}>
            {t('setupFinishAction')}
          </Button>,
        ]}
      />
    )
  } else if (error) {
    content = (
      <Result
        status="error"
        title={t('labels.errorTitle')}
        subTitle={error}
        extra={[
          <Button onClick={() => setError(null)} type="primary">
            {t('actions.goBack')}
          </Button>,
        ]}
      />
    );
  } else {
    content = (
      <Space direction="vertical" size="large">
        <Typography.Text>
          {t('farmHashPromptDescription')}
        </Typography.Text>
        <FarmHashInput
          disabled={loading}
          onChange={setInputState}
        />
        <Button
          type="primary"
          disabled={!valid}
          onClick={onSubmit}
          loading={loading}
        >
          {loading ? t('hubRegistrationInProgress') : t('actions.continue') }
        </Button>
      </Space>
    )
  }

  return (
    <HubPage
      title={t('title')}
      subTitle={t('subTitle')}
      centered
    >
      <Row>
        <Col span={12} offset={6}>
          {content}
        </Col>
      </Row>
    </HubPage>
  )
}
