import React, {FC} from 'react';
import { Switch, Route, Redirect } from 'react-router-dom';
import AboutHubPage from './AboutHubPage';
import SoftwareUpdatePage from './SoftwareUpdatePage';
import BackupsPage from "./BackupsPage";
import MonitoringSettingsPage from './MonitoringSettingsPage';
import HubPage from '../../core/HubPage';
import {useTranslation} from "react-i18next";
import SystemConfigPage from "./SystemConfigPage";


const menuItems = [
  {
    label: 'sections.systemConfig',
    to: '/settings/system'
  },
  {
    label: 'sections.monitoring',
    to: '/settings/monitoring'
  },
  {
    label: 'sections.backup',
    to: '/settings/backup'
  },
  {
    label: 'sections.softwareUpdate',
    to: '/settings/update'
  },
  {
    label: 'sections.aboutHub',
    to: '/settings/about'
  }
]

const SettingsContainer: FC = () => {
  const { t } = useTranslation('settings');
  return (
    <HubPage
      title={t('title')}
      subTitle={t('subTitle')}
      menuItems={menuItems}
      i18Namespace="settings"
    >
      <Switch>
        <Route exact path="/settings/about" component={AboutHubPage} />
        <Route exact path="/settings/update" component={SoftwareUpdatePage} />
        <Route exact path="/settings/backup" component={BackupsPage} />
        <Route exact path="/settings/monitoring" component={MonitoringSettingsPage} />
        <Route exact path="/settings/system" component={SystemConfigPage} />
        <Route>
          <Redirect to="/settings/system"/>
        </Route>
      </Switch>
    </HubPage>
  );
};

export default SettingsContainer;
