import React, {useState} from 'react';
import {useTranslation} from "react-i18next";
import {TFunction} from "i18next";
import {Button, Col, Empty, List, Row, Space, Tag} from 'antd';
import {DeleteFilled} from '@ant-design/icons';
import CredentialsInputModal from '../modals/CredentialsInputModal';
import {Credentials, ScanTarget} from "../../hub/scan-target";
import {
  CredentialsInputTarget,
  getScanTargetLabel,
  isCidrTarget, isRangeTarget
} from "../../types/devices";
import ScanTargetInput from "../form/ScanTargetInput";
import './DeviceAddressList.css'

const getTargetTag = (t: TFunction, target: ScanTarget) => {
  if (isCidrTarget(target)) {
    return <Tag color="purple" className="DeviceAddressList-item__badge">
      {t('addressList.targets.cidr')}
    </Tag>
  }

  if (isRangeTarget(target)) {
    return <Tag color="orange" className="DeviceAddressList-item__badge">
    {t('addressList.targets.range')}
    </Tag>
  }

  return <Tag color="blue" className="DeviceAddressList-item__badge">
    {t('addressList.targets.ip')}
  </Tag>
}

interface CredentialInputParams {
  visible: boolean
  target?: CredentialsInputTarget|null,
  value?: Credentials|null,
}

interface DeviceAddressListProps {
  values: ScanTarget[]
  onChange: (newValues: ScanTarget[]) => void
}

const DeviceAddressList: React.FC<DeviceAddressListProps> = ({values, onChange} ) => {
  const { t } = useTranslation('devicesPage');
  const [credModalParams, setCredModalParams] = useState<CredentialInputParams>({
    visible: false
  })

  const onDeviceRemove = (i: number) => {
    const newArr = [...values];
    newArr.splice(i, 1);
    onChange(newArr);
  }

  const onCredentialAdd = (t: CredentialsInputTarget, credentials: Credentials) => {
    const {key} = t;
    onChange(values.map((v, i) => {
      if (i === key) {
        return {...v, credentials};
      }
      return v;
    }));
    setCredModalParams({visible: false});
  }

  const onCredentialRemove = (t: CredentialsInputTarget) => {
    const {key} = t;
    onChange(values.map((v, i) => {
      if (i !== key) {
        return v;
      }
      let newVal = {...v};
      delete newVal.credentials;
      return newVal;
    }));

    setCredModalParams({visible: false});
  }

  const {visible, target, value} = credModalParams;
  return <Space direction="vertical" style={{width: '100%'}} size="middle">
    <ScanTargetInput onAdd={v => onChange([...values, v])}/>
    <List
      size="small"
      dataSource={values}
      bordered={false}
      style={{minHeight: 166}}
      locale={{
        emptyText: (
          <Empty
            image={Empty.PRESENTED_IMAGE_SIMPLE}
            description={t('addressList.empty')}
          />
        )
      }}
      renderItem={(item: ScanTarget, key: number) => {
        return <List.Item>
          <Row justify="space-between" style={{width: '100%'}}>
            <Col flex={4}>
              <Space>
                <>{getTargetTag(t, item)}</>
                <span className="text-monospace">{getScanTargetLabel(item)}</span>
              </Space>
            </Col>
            <Col>
              <Space>
                <Button
                  size="small"
                  type="text"
                  className="btn-icon"
                  onClick={() => {
                    setCredModalParams({
                      visible: true,
                      target: {key, item},
                      value: item.credentials,
                    })
                  }}
                >
                  {
                    t(item.credentials ?
                    'addressList.actions.changeCredentials' :
                    'addressList.actions.addCredentials')
                  }
                </Button>
                <Button
                  size="small"
                  type="text"
                  className="btn-icon btn-icon-danger"
                  title={t('addressList.actions.removeAddr')}
                  icon={<DeleteFilled />}
                  onClick={() => onDeviceRemove(key)}
                />
              </Space>
            </Col>
          </Row>
        </List.Item>
      }}
    />
    <CredentialsInputModal
      isVisible={visible}
      target={target}
      value={value}
      onCancel={() => setCredModalParams({visible: false})}
      onRemove={onCredentialRemove}
      onSave={onCredentialAdd}
    />
  </Space>
}

export default DeviceAddressList;
