import {IPTarget, ScanTarget} from "../hub/scan-target";
import {validateIP} from "./validate";
import {isIpTarget} from "../types/devices";

const CSV_DELIMITER = ',';
const allowedTypes = [
  'text/plain',
  'text/csv',
  'application/vnd.ms-excel'
];

const fileTypeValid = (type: string) => {
  if (!type.length) {
    return true;
  }

  return allowedTypes.includes(type);
}

const checkFileType = type => (
  fileTypeValid(type) ? Promise.resolve() : Promise.reject(`invalid file type ${type}`)
)

const splitLines = (str: string) => str.split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0)

const readTextAsync = (f: File): Promise<string> => new Promise((res, rej) => {
  const reader = new FileReader();
  reader.addEventListener('load', r => {
    res(reader.result as string)
  });
  reader.addEventListener('error', rej);
  reader.readAsText(f);
});

const parseIpTarget = (str: string): IPTarget => {
  const chunks = str.split(CSV_DELIMITER)
    .map(v => v.trim())
    .filter(v => !!v.length);

  const [ip, username, password] = chunks;
  if (!validateIP(ip)) {
    throw new Error(`Invalid IP address: ${ip}`);
  }

  if (chunks.length === 1) {
    return {ip};
  }

  if (!username?.length || !password?.length) {
    throw new Error(`Line "${str}" should contain both username and password`);
  }

  return {ip, credentials: {username, password}}
};

/**
 * Parses list of IPs to scan from selected file.
 * @param f File from input
 */
export const scanTargetsFromFile = (f: File): Promise<IPTarget[]> => {
  console.log(`reading ${f.name} ${f.type}`);
  return checkFileType(f.type)
    .then(() => readTextAsync(f))
    .then(txt => splitLines(txt))
    .then(lines => lines.map(l => parseIpTarget(l)))
};

/**
 * Removes duplicate values from scan targets list.
 *
 * Currently only checks unique IPs, but used only with scanTargetsFromFile.
 * So, it's okay for now.
 * @param all
 */
export const filterUniqueTargets = (all: ScanTarget[]): ScanTarget[] => {
  const uniqIps = new Map<string, IPTarget>();
  const restItems: ScanTarget[] = [];

  all.forEach(t => {
    if (!isIpTarget(t)) {
      restItems.push(t);
      return;
    }

    // respect only last-inserted item
    uniqIps.set(t.ip, t)
  })

  const ips = Array.from(uniqIps.values());
  return [...restItems, ...ips];
};
