import React from 'react';
import ReactDOM from 'react-dom';
import './index.less';
import App from './App';
import * as serviceWorker from './serviceWorker';
import {createI18nInstance} from "./locale";
import {createStore} from "./store/configure";
import {Provider} from "react-redux";
import {PersistGate} from "redux-persist/integration/react";
import LocaleSyncGate from "./locale/LocaleSyncGate";

let i18nInstance = createI18nInstance();
const [store, persistor] = createStore({ i18nInstance });

ReactDOM.render(
  <Provider store={store}>
    <PersistGate persistor={persistor}>
      <LocaleSyncGate loading="Loading..." store={store} i18nInstance={i18nInstance}>
        <App />
      </LocaleSyncGate>
    </PersistGate>
  </Provider>,
  document.getElementById('root')
);

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://bit.ly/CRA-PWA
serviceWorker.unregister();
