import React, {useEffect, useState} from 'react';
import {Button, Input, Select} from 'antd';
import { Query, selectOptions, logEntryOwnProperties } from './search';
import './LogFilter.less';
import {useTranslation} from "react-i18next";

const customSearchOptionKey = "custom";

interface LogFilterProps {
  onFilter: (q: Query) => void
  onReset: () => void
  disabled?: boolean
}

const LogFilter: React.FC<LogFilterProps> = ({disabled, onFilter, onReset}) => {
  const { t } = useTranslation('logView');
  const [selectedPreset, setSelectedPreset] = useState("message");
  const [searchKey, setSearchKey] = useState("message");
  const [searchValue, setSearchValue] = useState<string>('');
  const [isDirty, setDirty] = useState(false);
  const [isValid, setValid] = useState(false);

  const onSelectChange = (key: string) => {
    setSelectedPreset(key);
    setSearchKey(key === customSearchOptionKey ? "" : key);
    setSearchValue("");
  }

  const onSubmit = () => {
    setDirty(true);
    const ownProperty = logEntryOwnProperties.has(searchKey);
    onFilter({
      key: searchKey,
      value: searchValue,
      isField: !ownProperty,
    });
  }

  useEffect(() => {
    setValid(!!searchKey.length && !!searchValue.length);
  }, [searchKey, searchValue, setValid]);

  return <div className="LogFilter">
      <Input.Group compact style={{width: '100%', display: 'flex'}}>
        <Select
          style={{minWidth: 180}}
          value={selectedPreset}
          onChange={onSelectChange}
          disabled={disabled}
        >
          {selectOptions.map(key => (
            <Select.Option key={key} value={key}>{t(`filters.${key}`)}</Select.Option>
          ))}
          <Select.Option key="custom" value={customSearchOptionKey}>
            {t('filters.custom')}
          </Select.Option>
        </Select>
        {
          selectedPreset === customSearchOptionKey ?
            (
              <Input
                placeholder={t('labels.key')}
                onChange={({target}) => setSearchKey(target.value.trim())}
                value={searchKey}
                disabled={disabled}
              />
            ) : null
        }
        <Input
          placeholder={t('labels.value')}
          onChange={({target}) => setSearchValue(target.value.trim())}
          value={searchValue}
          disabled={disabled}
          suffix={
            <Button
              type="link"
              size="small"
              className="LogFilter__reset"
              hidden={!isDirty}
              onClick={() => {
                onReset();
                setDirty(false);
                setSearchValue("");
              }}
            >
              {t('search.actions.reset')}
            </Button>
          }
        />
        <Button
          disabled={disabled || !isValid}
          onClick={onSubmit}
        >
          {t('search.actions.search')}
        </Button>
      </Input.Group>
  </div>;
};

export default LogFilter;
