/**
 * DeviceSummary contains device basic info for display in devices list view
 */
import {Credentials} from "../scan-target";
export type SortOrder = 1 | -1;

export interface Sorting {
  key: DeviceKey
  order: SortOrder
}

export const sortEqual = (a?: Sorting | null, b?: Sorting | null) => {
  if (a === b) {
    return true;
  }

  return a?.key === b?.key && a?.order === b?.order;
}

export interface DeviceSummary {
  id: number
  ip: string
  mac: string
  rigId: number
  farmId: number
  type: string
  farmHash: string
  kind: string
  workerName: string
  username?: string|null
  password?: string|null
}

export interface VersionInfo {
    kernel: string
    firmware: string
    hardware: string
    software: string
}

export interface NIC {
    name: string
    ips: string
    netMask: string
    gateway: string
}

export interface BaseDeviceInfo {
    ip: string
    hostname: string
    mac: string
    type: string
    kind: string
    isStock: string
    hasHiveOS: boolean
    modelName: string
    version: VersionInfo
}

export interface AddDevicesResponse {
  duplicates?: string[]
}

export interface DeviceInfoChanges {
  ip: string
  username?: string|null
  password?: string|null
}

export interface DeviceScanInfo extends BaseDeviceInfo {
  exists: boolean
  credentials?: Credentials
}

export interface Device extends BaseDeviceInfo {
  farmHash: string
  network: NIC[]
}

export type DeviceKey = 'rigId' | 'ip' | 'mac' | 'type' | 'workerName';

export interface DeviceSearchQuery {
  key: string
  query: string
}

export interface DeviceQuery {
  limit: number
  offset: number
  sorting?: {
    key: DeviceKey
    order: SortOrder
  } | null
  search?: DeviceSearchQuery | null
}
