import React, {useContext, useState} from 'react';
import { format } from 'date-fns';
import {Typography} from "antd";
import {CaretUpFilled, CaretDownFilled} from '@ant-design/icons';
import {LogRecord} from "../../../hub/log";
import './LogEntry.less';
import LogEntryDetails from "./LogEntryDetails";
import {DateFnsLocaleContext} from "../../../locale";

const dateFormat = 'dd MMMM yyyy HH:mm:ss';

interface LogEntryProps{
  record: LogRecord
}

const LogEntry: React.FC<LogEntryProps> = ({record}) => {
  const [isExpanded, setExpanded] = useState(false);
  const {time, level, tag, message} = record;
  const locale = useContext(DateFnsLocaleContext);
  return (
    <div className={`LogEntry LogEntry--${level}`}>
      <div className="LogEntry__header">
        <div className="LogEntry__label text-monospace">{level[0].toUpperCase()}</div>
        <div className="LogEntry__summary">
          <Typography.Text className="LogEntry__message">{message}</Typography.Text>
        </div>
        <div className="LogEntry__tag">
          {tag}
        </div>
        <div className="LogEntry__date">
          {format(time, dateFormat, {locale})}
        </div>
        <button className="LogEntry__expand" onClick={() => setExpanded(!isExpanded)}>
          { isExpanded ? <CaretUpFilled /> : <CaretDownFilled />}
        </button>
      </div>
      <LogEntryDetails record={record} visible={isExpanded} />
    </div>
  )
};

export default LogEntry;
