import React, {useState, useEffect} from 'react';
import {useTranslation} from "react-i18next";
import {TFunction} from "i18next";
import {Button, Input, Select, Tooltip} from 'antd';
import {InfoCircleOutlined} from "@ant-design/icons";
import {validateCIDR, validateIP} from "../../util/validate";
import {ScanTarget} from "../../hub/scan-target";

const {Option} = Select;

enum InputLayout {
  IP = 'ip',
  CIDR = 'cidr',
  RANGE = 'range'
}

const INITIAL_INPUT_VALUE: InputValue = {value: '', dirty: false};
interface InputValue {
  value: string
  dirty: boolean
}

interface ScanTargetInputProps extends React.HTMLAttributes<HTMLDivElement>{
  onAdd: (t: ScanTarget) => void
}

const getInputPlaceHolder = (t: TFunction, layout: InputLayout) => {
  switch (layout) {
    case InputLayout.IP:
      return t('scanTargetInput.placeholders.ip');
    case InputLayout.CIDR:
      return t('scanTargetInput.placeholders.cidr');
    case InputLayout.RANGE:
      return t('scanTargetInput.placeholders.startIP');
    default:
      return;
  }
}

const ScanTargetInput: React.FC<ScanTargetInputProps> = ({onAdd, ...props}) => {
  const { t } = useTranslation('devicesPage');
  const [layout, setLayout] = useState<InputLayout>(InputLayout.IP);
  const [primaryValue, setPrimaryValue] = useState<InputValue>(INITIAL_INPUT_VALUE);
  const [secondaryValue, setSecondaryValue] = useState<InputValue>(INITIAL_INPUT_VALUE);
  const [validationStatus, setValidationStatus] = useState<[boolean, boolean]>([false, false]);

  useEffect(() => {
    // reset data on type change
    setPrimaryValue(INITIAL_INPUT_VALUE);
    setSecondaryValue(INITIAL_INPUT_VALUE);
  }, [layout, setPrimaryValue, setSecondaryValue]);

  useEffect(() => {
    // validate on change
    const primaryValid = layout === InputLayout.CIDR ? validateCIDR(primaryValue.value) : validateIP(primaryValue.value);
    const secondaryValid = layout === InputLayout.RANGE ? validateIP(secondaryValue.value) : true;
    setValidationStatus([primaryValid, secondaryValid]);
  }, [setValidationStatus, layout, secondaryValue, primaryValue]);

  const onSubmit = () => {
    if (!isValid) return;
    const target: ScanTarget = (() => {
      switch (layout) {
        case InputLayout.IP:
          return {ip: primaryValue.value};
        case InputLayout.CIDR:
          return {cidr: primaryValue.value};
        case InputLayout.RANGE:
          return {
            from: primaryValue.value,
            to: secondaryValue.value,
          };
        default:
          // probably will never occur, but just in case...
          throw new Error('ScanTargetInput: unknown layout type');
      }
    })();

    onAdd(target);
    setPrimaryValue(INITIAL_INPUT_VALUE);
    setSecondaryValue(INITIAL_INPUT_VALUE);
  };

  const [firstValid, secondValid] = validationStatus;
  const isValid = layout === InputLayout.RANGE ? firstValid && secondValid : firstValid;
  return <Input.Group compact style={{width: '100%', display: 'flex'}} {...props}>
    <Select
      style={{width: '130px'}}
      defaultValue={InputLayout.IP}
      onChange={setLayout}
    >
      <Option value={InputLayout.IP}>{t('scanTargetInput.options.ip')}</Option>
      <Option value={InputLayout.CIDR}>{t('scanTargetInput.options.cidr')}</Option>
      <Option value={InputLayout.RANGE}>{t('scanTargetInput.options.range')}</Option>
    </Select>
    <Input
      placeholder={getInputPlaceHolder(t, layout)}
      value={primaryValue.value}
      onChange={v => setPrimaryValue({value: v.target.value, dirty: true})}
      suffix={
        <Tooltip title={t('scanTargetInput.validationError')}>
          <InfoCircleOutlined className="text-danger" style={{ display: !firstValid && primaryValue.dirty ? 'block' : 'none'}} />
        </Tooltip>
      }
    />
    {layout !== InputLayout.RANGE ? null : (
      <Input
        placeholder={t('scanTargetInput.placeholders.endIP')}
        value={secondaryValue.value}
        onChange={v => setSecondaryValue({value: v.target.value, dirty: true})}
        suffix={
          <Tooltip title={t('scanTargetInput.validationError')}>
            <InfoCircleOutlined
              className="text-danger"
              style={{display: !secondValid && secondaryValue.dirty ? 'block' : 'none' }}
            />
          </Tooltip>
        }
      />
    )}
    <Button type="text" disabled={!isValid} onClick={onSubmit}>
      {t('actions.add')}
    </Button>
  </Input.Group>
}

export default ScanTargetInput;
