import React, {FC} from 'react';
import { NavLink } from 'react-router-dom';
import './HubHorizontalMenu.less';
import {useTranslation} from "react-i18next";

type HubHorizontalMenuLayout = 'small' | 'regular';

export interface HubMenuItem {
  label: string
  to: string
  target?: string
  exact?: boolean
  strict?: boolean
  isActive?: (match, location) => boolean
}

interface HubHorizontalMenuProps {
  className?: string
  layout?: HubHorizontalMenuLayout
  items: HubMenuItem[]
  i18Namespace?: string | string[]
}

const getClassName = (layout: HubHorizontalMenuLayout = 'small', optClassName?: string) => (
  `HubHorizontalMenu HubHorizontalMenu--${layout}${optClassName ? ' ' + optClassName : ''}`
);

const HubHorizontalMenu: FC<HubHorizontalMenuProps> = ({layout, className, items, i18Namespace}) => {
  const { t } = useTranslation(i18Namespace);
  return (
    <ul className={getClassName(layout, className)}>
      {items.map((v, i) => (
        <li key={i} className="HubHorizontalMenu__item">
          <NavLink
            to={v.to}
            target={v.target}
            exact={v.exact}
            strict={v.strict}
            isActive={v.isActive}
            className="HubHorizontalMenu__link"
            activeClassName="HubHorizontalMenu__link--active"
          >
            {t(v.label)}
          </NavLink>
        </li>
      ))}
    </ul>
  );
};

export default HubHorizontalMenu;
