import React from "react";
import { Locale as AntLocale } from "antd/lib/locale-provider";
import { Locale as DateFnsLocale } from 'date-fns';
import * as dateFnsLocale from 'date-fns/locale';

/**
 * Default language
 */
export const fallbackLanguage = 'en';

/**
 * List of languages for languages selector
 */
export const languagesList: {[key: string]: string} = {
  'en': 'English',
  'ru': 'Русский',
  'uk': 'Українська',
  'zh': '中國人'
}

/**
 * Ant Design library locale resources
 */
const antLocales: {[key in keyof typeof languagesList]: AntLocale} = {
  'en': require('antd/lib/locale/en_US').default,
  'ru': require('antd/lib/locale/ru_RU').default,
  'uk': require('antd/lib/locale/uk_UA').default,
  'it': require('antd/lib/locale/it_IT').default,
  'pl': require('antd/lib/locale/pl_PL').default,
  'fr': require('antd/lib/locale/fr_FR').default,
  'zh': require('antd/lib/locale/zh_CN').default
};

/**
 * Date-fns locale resources
 */
const dateLocales: {[key in keyof typeof languagesList]: DateFnsLocale} = {
  'en': dateFnsLocale.enUS,
  'ru': dateFnsLocale.ru,
  'uk': dateFnsLocale.uk,
  'it': dateFnsLocale.it,
  'pl': dateFnsLocale.pl,
  'fr': dateFnsLocale.fr,
  'zh': dateFnsLocale.zhCN
};


/**
 * Returns locale resource for ant-design library configuration provider.
 * @param lang language name
 */
export const getAntLocale = (lang: string) => (
  antLocales[lang in antLocales ? lang : fallbackLanguage]
);

/**
 * Returns locale resource for date-fns.
 * @param lang language name
 */
export const getDateLocale = (lang: string) => (
  dateLocales[lang in dateLocales ? lang : fallbackLanguage]
);

export const DateFnsLocaleContext = React.createContext<Locale>(dateLocales[fallbackLanguage]);
