import React from 'react';

import {Button, Modal, List, Typography} from 'antd';
import {useTranslation} from "react-i18next";

interface Props {
  visible?: boolean,
  ips?: string[],
  onClose: () => void
}

const UpdatedDevicesModal: React.FC<Props> = ({visible, ips, onClose}) => {
  const { t } = useTranslation('devicesPage');
  return (
    <Modal
      title={t('updatedDevice.title')}
      visible={visible}
      closable={true}
      onCancel={onClose}
      centered={true}
      maskClosable={true}
      footer={(
        <Button type="primary" onClick={onClose}>
          {t('actions.ok')}
        </Button>
      )}
    >
      <p>
        {t('updatedDevice.description', {count: ips?.length})}
      </p>
      <List
        size="small"
        dataSource={ips}
        renderItem={item => (
          <List.Item>
            <Typography.Link
              className="text-monospace"
              href={`//${item}`}
              target="_blank">
              {item}
            </Typography.Link>
          </List.Item>
        )}
      />
    </Modal>
  );
};

export default UpdatedDevicesModal;
