import { RPCClient, Response } from './rpc';
import HubService from './service';
import DevicesService from './devices/service';
import UpdateService from "./update/service";
import SettingsService from './settings/service';
import BackupsService from "./backups/service";

export * from './devices/service';
export * from './devices/types';
export * from './settings/types';
export * from './backups/types';
export * from './urls';
export type { DeviceKindLabelPair } from './requests';

const API_HOST = process.env['REACT_APP_API_HOST'] ?? window.location.origin
const API_ENDPOINT = '/rpc';
const client = new RPCClient(API_HOST + API_ENDPOINT);


// Hub Version
export const HUB_VERSION = process.env.REACT_APP_VERSION || 'local';

/**
 * Hub Service client
 */
export const hubService = new HubService(client);

/**
 * Devices management client
 */
export const devicesService = new DevicesService(client);

/**
 * Software update service
 */
export const updateService = new UpdateService(client);

/**
 * Hub Settings service
 */
export const settingsService = new SettingsService(client);

/**
 * Data backup & restore service
 */
export const backupsService = new BackupsService(client);

/**
 * Checks if response has error
 * @param r Response
 */
export const hasError = (r: Response<any>) => !!r.error;

/**
 * Wraps RPC response and throws an exception if response contains an error.
 * Returns response data if call is successful.
 * @param r Response promise
 * @example
 * const result = getResult(devicesService.getDevicesCount())
 */
export const getResult = async <T={}>(r: Promise<Response<T>>) : Promise<T> => {
  const resp = await r;
  if (hasError(resp)) {
    throw new Error(resp.error?.message);
  }

  return resp.result;
};
