import {fallbackLanguage, languagesList} from "./resources";

const getBrowserLanguages = () => {
  if (navigator.languages) {
    return Array.from(navigator.languages);
  }

  if (navigator.language) {
    return [navigator.language];
  }

  if (navigator['userLanguage']) {
    return [navigator['userLanguage']];
  }

  return [];
};

/**
 * Returns client's browser languages that supported by the app.
 */
export const getSupportedLanguages = () => {
  const userLanguages = getBrowserLanguages();
  if (!userLanguages?.length) {
    return null;
  }

  // Drop country from locale section and leave only a language.
  const knownLanguages = userLanguages
    .map(v => v.toLowerCase().split('-')[0])
    .filter(v => languagesList.hasOwnProperty(v));

  if (!knownLanguages.length) {
    return null;
  }

  return Array.from(new Set(knownLanguages));
}

/**
 * Returns primary browser language that supported by the app.
 *
 * Returns fallback value if none of browser languages are supported.
 */
export const getSupportedPrimaryLanguage = () => {
  const supportedLanguages = getSupportedLanguages();
  if (!supportedLanguages?.length) {
    return fallbackLanguage;
  }

  return supportedLanguages[0];
};
