import React, {FC} from 'react';
import type {PageHeaderProps} from "antd/lib/page-header";
import {PageHeader} from "antd";
import './HubPageHeader.less';

type HubPageHeaderLayout = 'compact' | 'default';
interface HubPageHeaderProps extends PageHeaderProps {
  layout?: HubPageHeaderLayout
  centered?: boolean
}

const getClassName = (layout: HubPageHeaderLayout = 'default', centered = false) => {
  let name =  `HubPageHeader HubPageHeader--${layout}`;
  if (centered) {
    name += ' HubPageHeader--centered'
  }

  return name
};

const HubPageHeader: FC<HubPageHeaderProps> = props => (
  <PageHeader className={getClassName(props.layout, props.centered)} {...props} />
);

export default HubPageHeader;
