import React from 'react';
import './HubContainer.less';

interface HubContainerProps extends React.HTMLAttributes<HTMLDivElement>{}

const CLASS_NAME = 'HubContainer';

export default (props: HubContainerProps) => {
  let className = props.className ? `${CLASS_NAME} ${props.className}` : CLASS_NAME;
  let newProps = {...props, ...{className}};
  return <div {...newProps}>
    {props.children}
  </div>
}
