import { combineReducers } from "redux";
import {Action, ActionType} from "./actions";
import {State} from "./state";
import {getSupportedPrimaryLanguage} from "../locale";

const reducers = {
  language: (state: string, action: Action) => {
    switch (action.type) {
      case ActionType.ChangeLanguage:
        return action.payload;
      default:
        return state ?? 'en';
    }
  }
};

export const getInitialState = (): State => ({
  language: getSupportedPrimaryLanguage()
});

export const createRootReducer = () => combineReducers(reducers);
