import React, {ReactNode, createRef} from 'react';
import {Button} from "antd";
import {UploadOutlined} from "@ant-design/icons";

const DEFAULT_ICON = <UploadOutlined />
const DEFAULT_LABEL = 'Open file'

interface FileImportButtonProps {
  type?: 'primary' | 'text' | 'link'
  label?: string
  accept?: string
  hidden?: boolean
  disabled?: boolean
  multiple?: boolean
  icon?: ReactNode
  style?: React.CSSProperties
  onChange?: (files: FileList|null) => void
}

export default function FileOpenButton(props: FileImportButtonProps) {
  const {
    type,
    disabled,
    hidden,
    label,
    icon,
    style,
    onChange
  } = props;
  const inputRef = createRef<HTMLInputElement>();

  return (
    <div
      className="FileImportButton"
      style={{display: hidden ? 'none' : 'inline-block', ...style}}
    >
      <Button
        type={type}
        icon={icon ?? DEFAULT_ICON}
        disabled={disabled || hidden}
        onClick={() => inputRef.current?.click()}
      >
        {label ?? DEFAULT_LABEL}
      </Button>
      <input
        type="file"
        accept={props.accept}
        multiple={props.multiple}
        ref={inputRef}
        style={{display: 'none'}}
        disabled={disabled || hidden}
        onChange={e => {
          onChange && onChange(e.target.files);
        }}
      />
    </div>
  );
}
