import React from 'react';
import './SettingsSection.less';

const SETTINGS_SECTION_DEFAULT_ORIENTATION = 'horizontal';

interface SettingsSectionProps {
  /**
   * Section label
   */
  label: string

  /**
   * Section content orientation. Horizontal is default.
   *
   * In horizontal orientation, content is displayed aside the description.
   * In vertical - under.
   */
  orientation?: 'horizontal' | 'vertical'

  /**
   * Section description. Can be string or react node
   */
  description?: string | React.ReactNode

  /**
   * Additional actions
   */
  actions?: React.ReactNode[]

  /**
   * Hide
   */
  hidden?: boolean
}

/**
 * Is settings parameter section component which has label, description and control.
 *
 * Control (one or many selects for ex.) should be passed as children node.
 *
 * @example ```
 * <SettingsSection
 *  label="Name"
 *  description="Your name and surname"
 * >
 *  <input type="text"/>
 * </SettingsSection>
 * ```
 * @param props SettingsSectionProps
 * @constructor
 */
const SettingsSection: React.FC<SettingsSectionProps> = ({ label, description, hidden, children, orientation, actions }) => (
  hidden ? null : (
    <section className={`SettingsSection SettingsSection--${orientation}`}>
      {label && (
        <div className="SettingsSection__info">
          <h3 className="SettingsSection__label">
            {label}
          </h3>
          {description && (
            <div className="SettingsSection__description">
              {description}
            </div>
          )}
        </div>
      )}
      <div className="SettingsSection__container">
        <div className="SettingsSection__control">
          {children}
        </div>
        {actions && (
          <div className="SettingsSection__actions">
            {actions}
          </div>
        )}
      </div>
    </section>
  )
);

SettingsSection.defaultProps = {
  orientation: SETTINGS_SECTION_DEFAULT_ORIENTATION
};

export default SettingsSection;
