import { LogRecord } from '../../../hub/log';

export interface Query {
  key: string
  isField: boolean
  value: string
}


// list of properties that belongs to LogFilter itself.
export const logEntryOwnProperties = new Set([
  "level", "tag", "message"
])

export const selectOptions = [
  'level',
  'tag',
  'message',
  'ip',
  'mac',
  'rig_id'
];

export const filterRecords = (query: Query, items: LogRecord[]): LogRecord[] => (
  items.filter(item => {
    const searchSrc = query.isField ? item.fields : item;
    if (!searchSrc) {
      return false
    }

    const searchValue = searchSrc[query.key];
    return (!!searchValue) && searchValue.toString().startsWith(query.value);
  })
);
