import React from 'react';
import { Field } from 'formik';
import ItemsListInput, { ItemsListInputProps } from './ItemsListInput';

interface Props extends ItemsListInputProps {}

/**
 * FormikItemsListInput is a Formik adapter for ItemsListInput
 */
const FormikItemsListInput: React.FC<Props> = ({name, id, onChange, onBlur, ...props}) => (
  <Field name={name}>
    {({ field: { value, onChange, onBlur }, form: { setFieldTouched } }) => (
      <ItemsListInput
        name={name}
        value={value}
        onChange={changes => {
          const syntheticEvent = {
            target: {
              id, name,
              value: changes
            }
          };
          onChange(syntheticEvent);
          setFieldTouched(name);
        }}
        onBlur={onBlur}
        {...props}
      />
    )}
  </Field>
);

export default FormikItemsListInput;
