export enum ReleaseChannel {
  Stable = 'stable',
  Beta = 'beta',
  Testing = 'testing'
}

export const ReleaseChannels = [
  ReleaseChannel.Stable,
  ReleaseChannel.Beta,
  ReleaseChannel.Testing
];

export enum EventType {
  Idle      = 0,
  Error     = 1,
  Download  = 2,
  Install   = 3,
  Reboot    = 4
}

export interface VersionInfo {
  version: string
  build: string
  type: ReleaseChannel
}

export interface Artifact {
  url: string
  md5: string
  type: string
}

export interface InstallPackage extends VersionInfo {
  artifact: Artifact
}

export interface UpdateChannel {
  channel: ReleaseChannel
}

export interface AvailableReleaseChannels {
  channels: ReleaseChannel[]
}

export interface UpdateInfo {
  available: boolean
  otaSupported: boolean
  package?: InstallPackage
}

export interface UpgradeProgress<T=any> {
  type: EventType
  message?: string
  data?: T
}

export interface DownloadProgress {
  totalBytes: number
  downloadedBytes: number
  chunkSize: number
}

export interface ChangeLog {
  beta: boolean,
  date: string,
  description: string,
  version: string
}
export interface ChangeLogList {
data: ChangeLog[]
}