import React, {useState, useEffect} from 'react';
import {
  Button, Result, Select, Typography, Row, Col, message
} from 'antd';
import {
  WorkerNameSource,
  settingsService,
  hubService,
  Configuration,
  ConfigurationDelta
} from "../../../hub";
import SettingsSection from "../../form/SettingsSection";
import PageActionsFooter from "../../containers/PageActionsFooter";
import {useLoadState} from "../../../util/hooks";
import {portalName} from "../../../env";
import FarmHashInput from "../../form/FarmHashInput";
import {Trans, useTranslation} from "react-i18next";
import SettingsSectionPlaceholder from "../../form/SettingsSectionPlaceholder";

const EMPTY_DELTA = {};

const initialFarmHashFieldState = {
  valid: false,
  loading: false,
  value: '',
}

export default function MonitoringSettingsPage() {
  const { t } = useTranslation('settings');
  const [loadState, setError, setLoading] = useLoadState(true);
  const [delta, setDelta] = useState<ConfigurationDelta>(EMPTY_DELTA);
  const [isSaving, setSaving] = useState(false);
  const [farmHashFieldState, setFarmHashFieldState] = useState(initialFarmHashFieldState);

  const [config, setConfig] = useState<Configuration>();

  useEffect(() => {
    setLoading(true);
    settingsService.getSettings().then(cfg => {
      setLoading(false);
      setConfig(cfg);
    }).catch(err => setError(err));
    // eslint-disable-next-line
  }, []);

  const getConfigValue = (k: keyof Configuration) => (
    delta?.[k] ?? config?.[k]
  );

  const saveChanges = () => {
    if (!Object.keys(delta).length) return;
    setSaving(true);
    settingsService.updateSettings(delta).then(() => {
      setSaving(false);
      setConfig({...config, ...delta} as Configuration);
      setDelta(EMPTY_DELTA);
      message.success(t('messages.saveSuccess'));
    }).catch(err => {
      setSaving(false);
      message.error(t('messages.saveFailed', {message: err.message}));
    })
  };

  const registerHub = () => {
    const {value, valid} = farmHashFieldState;
    if (!valid) return;

    setFarmHashFieldState({value, valid, loading: true});
    hubService.setupHub({hubFarmHash: value, force: true})
      .then(() => {
        setFarmHashFieldState(initialFarmHashFieldState);
        message.success(t('messages.registerSuccess', {farmHash: value}));
      }).catch(err => {
        message.error(t('messages.registerFailed', {message: err?.message ?? err}));
        setFarmHashFieldState({value, valid, loading: false});
      });
  };

  const {loading, error} = loadState;
  if (loading) {
    return <>
      <SettingsSectionPlaceholder active={true} rows={4} />
      <SettingsSectionPlaceholder active={true} rows={1} />
    </>
  }

  if (error) {
    return <Result
      status="error"
      title={t('labels.errorTitle')}
      subTitle={error?.message ?? error.toString()}
    />
  }

  return (<>
    <SettingsSection
      label={t('workerNameSource.label')}
      description={
        <>
          <p>{t('workerNameSource.description', {portalName})}</p>
          <p>
            <Typography.Text type="warning">
              <Trans i18nKey="workerNameSource.disclaimer1" ns="settings">
                Doesn't work with <u>Avalon</u> and <u>Innosilicon</u> ASICs, as they don't provide their hostname.
              </Trans>
            </Typography.Text>
          </p>
          <Typography.Text type="warning">
            <Trans i18nKey="workerNameSource.disclaimer2" ns="settings">
              <b>Dangerous!</b> This parameter may affect flight sheets behavior.
            </Trans>
          </Typography.Text>
        </>
      }
    >
      <Select
        value={getConfigValue('workerNameSource')}
        onChange={workerNameSource => setDelta({...delta, workerNameSource})}
        disabled={isSaving}
      >
        <Select.Option value={WorkerNameSource.Remote}>{t('workerNameSource.options.useWorkerName', {portalName})}</Select.Option>
        <Select.Option value={WorkerNameSource.Hostname}>{t('workerNameSource.options.useHostname')}</Select.Option>
      </Select>
    </SettingsSection>
    <SettingsSection
      label={t('reRegisterHub.label')}
      description={t('reRegisterHub.description')}
    >
      <Row>
        <Col flex="auto">
          <FarmHashInput
            onChange={({value, valid}) => setFarmHashFieldState({...farmHashFieldState, value, valid})}
            disabled={isSaving || farmHashFieldState.loading}
            value={farmHashFieldState.value}
          />
        </Col>
        <Button
          style={{marginLeft: '5px'}}
          onClick={registerHub}
          disabled={!farmHashFieldState.valid || isSaving}
          loading={farmHashFieldState.loading}
        >
          {t(farmHashFieldState.loading ? "labels.registrationInProgress" : "actions.register")}
        </Button>
      </Row>
    </SettingsSection>
    <PageActionsFooter gravity="right">
      <Button
        loading={isSaving}
        disabled={!Object.keys(delta).length}
        onClick={saveChanges}
      >
        {t('actions.saveChanges')}
      </Button>
    </PageActionsFooter>
  </>);
}
