import React from "react";
import {Col, Input, Row} from "antd";
import FileOpenButton from "./FileOpenButton";

interface Props {
  label?: string
  placeholder?: string
  accept?: string
  hidden?: boolean
  disabled?: boolean
  value?: FileList|null|undefined
  onChange?: (files: FileList|null|undefined) => void
}

const FileSelectInput: React.FC<Props> = ({placeholder, value, hidden, disabled, ...btnProps }) => {
  if (hidden) {
    return <></>;
  }

  const label = value?.length ? value?.[0].name : '';
  return (
    <Row>
      <Col flex="auto">
        <Input
          type="text"
          readOnly={true}
          placeholder={placeholder}
          value={label}
          disabled={disabled}
        />
      </Col>
      <Col>
        <FileOpenButton
          icon={<></>}
          style={{marginLeft: '5px'}}
          disabled={disabled}
          {...btnProps}
        />
      </Col>
    </Row>
  );
};

export default FileSelectInput;
