import {useState} from 'react';

export interface LoadState {
  loading: boolean
  error?: any
}

type LoadStateHook = [LoadState, (error: any) => void, (loading: boolean) => void];

/**
 * useLoadState is simple page load state
 *
 * Example usage:
 *
 * ```
 * const [loadState, setError, setLoading] = useLoadState(true);
 *
 * loadData()
 *  .then(data => setLoading(false))
 *  .catch(err => setError(err))
 * ```
 */
export const useLoadState = (initialLoadState=false): LoadStateHook => {
  const [loadState, setLoadState] = useState<LoadState>({loading: initialLoadState});
  return [
    loadState,
    (error: string) => setLoadState({loading: false, error}),
    (loading: boolean) => setLoadState({loading}),
  ]
};

