import React, {FC} from 'react';
import {PageHeaderProps} from "antd/lib/page-header";
import HubHorizontalMenu, {HubMenuItem} from "../menus/HubHorizontalMenu";
import HubContainer from "./HubContainer";
import HubPageHeader from "./HubPageHeader";
import "./HubPage.less"

interface HubPageProps {
  title: React.ReactNode;
  subTitle?: React.ReactNode;
  extra?: React.ReactNode;
  centered?: boolean;
  menuItems?: HubMenuItem[]
  i18Namespace?: string | string[]
  children: React.ReactNode | React.ReactNode[];
}

const extractHeaderProps = props => {
  const {title, subTitle, extra, centered} = props;
  return {title, subTitle, extra, centered} as PageHeaderProps;
};

const HubPage: FC<HubPageProps> = ({menuItems, children, i18Namespace, ...props}) => (
  <>
    <div className="HubPage__header">
      <HubContainer>
        <HubPageHeader
          layout={menuItems?.length ? 'compact' : 'default'}
          {...extractHeaderProps(props)}
        />
        { menuItems?.length ? (
          <HubHorizontalMenu items={menuItems} i18Namespace={i18Namespace}/>
        ) : null}
      </HubContainer>
    </div>
    <HubContainer className="HubPage__content">
      {children}
    </HubContainer>
  </>
);

export default HubPage;
