import validateCidr from 'is-cidr';
import { isIP } from 'is-ip';

/* eslint-disable */
const SHA1_REGEX = /^[a-fA-F0-9]{40}$/;
const FILENAME_REGEX = /^([а-я\w\d])([а-я\w._\-+\d\s])+$/i;
const SOCKADDR_REGEX = /^(?:([0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}))?(:[0-9]{2,5})$/i;
const PATH_WIN_REGEX = /^(([a-zA-Z]\:)|(\\))(\\{1}|((\\{1})[^\\]([^\/:*?<>"|]*))+)$/i;
const PATH_UNIX_REGEX = /^((?:\/{1})?(?=[^\/\0])[^\/\0]+)*\/?$/i;
const DURATION_REGEX = /^([0-9]*(\.[0-9]*)?(ns|us|µs|ms|s|m|h)+)+$/;
/* eslint-enable */

export const validateFarmHash = (hash: string) => SHA1_REGEX.test(hash);
export const validateIP = (ip: string) => isIP(ip);
export const validateCIDR = (cidr: string) => !!validateCidr(cidr);
export const validateFileName = (fileName: string) => FILENAME_REGEX.test(fileName);

export const validatePathName = value => PATH_WIN_REGEX.test(value) || PATH_UNIX_REGEX.test(value)

export const validateDuration = v => DURATION_REGEX.test(v);

type validator = (val: string) => boolean;

export const validateOneOf = (...validators: validator[]) => (
  (val: string) => {
    const results = validators.map(fn => fn(val)).filter(v => v);
    return results.length > 0;
  }
);

export const validateIpOrCidr = validateOneOf(validateIP, validateCIDR);

export const validateSocket = (val: string) => {
  if (!SOCKADDR_REGEX.test(val)) {
    return false;
  }

  const [ip, port] = val.split(':');
  if (ip.length) {
    if (!isIP(ip)) {
      return false;
    }
  }

  const portNum = +port;
  if (portNum < 0 || portNum > 65535) {
    return false;
  }

  return true;
}

window['v'] = validatePathName;
