import React from 'react';
import { Link } from 'react-router-dom';
import {connect} from 'react-redux';
import {Menu, Layout, Typography} from 'antd';
import {useTranslation} from "react-i18next";
import {brandName, logoUrl, productTitle} from '../../env';
import {getMenuItems} from "./menu-items";
import LanguageSelector from "../misc/LanguageSelector";
import {changeLanguageDispatcher} from "../../store/dispatch";
import {DispatchProp} from "../../store/types";
import {State} from "../../store/state";
import "./HubHeader.less";

const { Header } = Layout;
const { Item } = Menu;

interface HubHeaderProps extends DispatchProp {
  language: string
  showMenu?: boolean
}

const HubHeader = connect<any, any, any, State>(({language}) => ({language}))(({showMenu, dispatch, language}: HubHeaderProps) => {
  const { t } = useTranslation('mainMenu');
  const menuItems = getMenuItems(language);

  return (
    <div className="HubHeader">
      <Header className="HubHeader__container HubContainer">
        <div className="HubHeader__logo">
          <img src={logoUrl} className="HubHeader__icon" alt={brandName}/>
          <span className="HubHeader__title">{productTitle}</span>
        </div>
        { showMenu ? (
          <Menu
            theme="dark"
            mode="horizontal"
            className="HubHeader__menu"
          >
            {
              Object.entries(menuItems).map(v => {
                const [key, params] = v;
                const {label, external, to} = params;

                return external ? (
                   <Item key={key}>
                     <Typography.Link href={to} target="_blank">
                       {t(label)}
                     </Typography.Link>
                   </Item>
                ) : (
                  <Item key={key}>
                    <Link to={to}>{t(label)}</Link>
                  </Item>
                );
              })
            }
          </Menu>
        ) : null}
        <LanguageSelector
          className="HubHeader__languageSelector"
          value={language}
          onChange={v => {
            dispatch(changeLanguageDispatcher(v));
          }}
        />
      </Header>
    </div>
  )
});

export default HubHeader;
