import React, {useState} from "react";
import {TFunction} from "i18next";
import {useTranslation} from "react-i18next";
import {Button, Col, Row, Modal, message} from "antd";
import {UploadOutlined} from "@ant-design/icons";
import FileSelectInput from "../../../form/FileSelectInput";
import SettingsSection from "../../../form/SettingsSection";
import {backupsService} from "../../../../hub";

const SQL_FILE_MIME = "application/sql,.sql";
const MAX_FILE_SIZE_BYTES = 50 * Math.pow(1024, 2); // 50MB
const MAX_FILE_SIZE_LABEL = "50MB";

const validateFileSize = (t: TFunction, f?: File|null) => {
  if (!f) {
    return false;
  }

  const {size, name} = f;
  if (!size) {
    Modal.error({
      title: t('import.errors.emptyFileTitle'),
      content: t('import.errors.emptyFileMessage', {name})
    });

    return false;
  }

  if (size > MAX_FILE_SIZE_BYTES) {
    Modal.error({
      title: t('import.errors.fileTooBigTitle'),
      content: (
        <>
          <p>{t('import.errors.fileTooBigMessage', {name})}</p>
          <p>{t('import.errors.fileTooBigHint', {MAX_FILE_SIZE_LABEL})}</p>
        </>
      )
    })
    return false;
  }

  return true;
}

const ImportBackupSection: React.FC<{disabled?: boolean, onChange?: () => void}> = ({disabled, onChange}) => {
  const { t } = useTranslation('backups');
  const [isLoading, setLoading] = useState(false);
  const [fileList, setFileList] = useState<FileList|null|undefined>();

  const uploadFile = async () => {
    const file = fileList?.item(0);
    if (!file) {
      return;
    }

    setLoading(true);
    backupsService.importBackup(file)
      .then(({fileName}) => {
        message.success({
          content: t('import.messages.importSuccess', {fileName})
        });
        onChange?.();
      })
      .catch(err => {
        Modal.error({
          title: t('import.messages.importFailed'),
          content: err.message ?? err.toString()
        });
      })
      .finally(() => {
        setLoading(false);
        setFileList(null);
      });
  };

  return (
    <SettingsSection
      label={t('import.label')}
      description={<>
        {t('import.description')}
      </>}
    >
      <Row>
        <Col flex="auto">
          <Row>
            <Col flex="auto">
              <FileSelectInput
                disabled={isLoading || disabled}
                placeholder={t('import.fileSelectPlaceholder')}
                label={t('import.fileSelectLabel')}
                accept={SQL_FILE_MIME}
                value={fileList}
                onChange={files => {
                  if (!validateFileSize(t, files?.item(0))) {
                    setFileList(null);
                    return;
                  }

                  setFileList(files);
                }}
              />
            </Col>
            <Col>
              <Button
                style={{marginLeft: "10px"}}
                icon={<UploadOutlined />}
                disabled={disabled || !fileList}
                loading={isLoading}
                onClick={uploadFile}
              >
                { t(isLoading ? 'import.uploadProgress' : 'import.uploadAction')}
              </Button>
            </Col>
          </Row>
        </Col>
      </Row>
    </SettingsSection>
  );
};

export default ImportBackupSection;
