import React, {useContext} from 'react';
import {useTranslation} from "react-i18next";
import { Table, Button, Typography, Space} from "antd";
import { DeleteFilled, PlayCircleFilled } from "@ant-design/icons";

import { format } from 'date-fns';
import {BackupFileInfo, backupsService} from "../../../hub";
import { humanFileSize } from "../../../util/formatters";
import {DateFnsLocaleContext} from "../../../locale";

type FileCallback = (fileName: string) => void;

const dateFormat = 'dd MMMM yyyy HH:mm:ss';

interface BackupsListProps {
  items: BackupFileInfo[]
  onItemSelect: FileCallback;
  onItemDelete: FileCallback;
  disabled?: boolean
  loading?: boolean;
}

const BackupsList: React.FC<BackupsListProps> = ({items, onItemSelect, onItemDelete, loading, disabled}) => {
  const { t } = useTranslation('backups');
  const locale = useContext(DateFnsLocaleContext);
  const columns = [
    {
      key: 'name',
      title: t('restore.columns.fileName'),
      render: v => (
        <Typography.Link
          className="text-monospace"
          href={backupsService.getBackupDownloadUrl(v.name)}
          target="_blank">
          {v.name}
        </Typography.Link>
      )
    },
    {
      title: t('restore.columns.sizeBytes'),
      key: 'sizeBytes',
      dataIndex: 'sizeBytes',
      width: '10%',
      sorter: (a, b) => a.sizeBytes - b.sizeBytes,
      render: v => humanFileSize(v)
    },
    {
      title: t('restore.columns.createdAt'),
      key: 'createdAt',
      dataIndex: 'createdAt',
      sorter: (a, b) => a.createdAt - b.createdAt,
      render: v => format(v, dateFormat, { locale })
    },
    {
      title: '',
      key: 'action',
      render: item => (
        <Space size="small">
          <Button
            size="small"
            type="text"
            title={t('restore.actions.restore')}
            className="btn-icon"
            icon={<PlayCircleFilled />}
            disabled={disabled}
            onClick={() => onItemSelect(item.name)}
          />
          <Button
            size="small"
            type="text"
            title={t('restore.actions.deleteBackup')}
            className="btn-icon"
            disabled={disabled}
            icon={<DeleteFilled />}
            onClick={() => onItemDelete(item.name)}
          />
        </Space>
      )
    }
  ];

  return (
    <Table
      size="small"
      columns={columns}
      rowKey={row => row.name}
      dataSource={items}
      loading={loading}
    />
  );
};

export default BackupsList;
