import React, {useState} from 'react';
import {Input, Tooltip} from "antd";
import Label from './Label';
import {validateFarmHash} from "../../util/validate";
import {InfoCircleOutlined} from "@ant-design/icons";
import './FarmHashInput.less';
import {useTranslation} from "react-i18next";

const FARM_HASH_EXAMPLE = '8151325dcdbae9e0ff95f9f9658432dbedfdb209';

interface FarmHashInputProps {
  disabled?: boolean
  value?: string
  placeholder?: string
  onChange: (e: FarmHashInputEvent) => void
}

export const DEFAULT_FARM_HASH_EVENT: FarmHashInputEvent = {valid: false, value: ''};

export interface FarmHashInputEvent {
  value: string
  valid: boolean
}

const FarmHashInput: React.FC<FarmHashInputProps> = ({onChange, value, disabled, placeholder}) => {
  const { t } = useTranslation('devicesPage');
  const [inputState, setInputState] = useState({
    dirty: false, valid: false, filled: !!value?.length
  });
  const {valid, dirty, filled} = inputState;
  return <Input
    placeholder={placeholder ?? t('farmHashInput.example', {example: FARM_HASH_EXAMPLE})}
    disabled={disabled}
    value={value}
    className={filled ? 'FarmHashInput--filled' : 'FarmHashInput'}
    onChange={(e) => {
      const {value} = e.target;
      const valid = validateFarmHash(value);
      const filled = value.length > 0;
      setInputState({dirty: true, valid, filled});
      onChange({value, valid});
    }}
    prefix={<Label disabled={disabled}>Farm Hash:</Label>}
    suffix={
      valid || !dirty ? null : (
          <Tooltip title={t('farmHashInput.validationError')}>
            <InfoCircleOutlined className="text-danger"/>
          </Tooltip>
      )
    }
  />
}

export default FarmHashInput;
