import { RPCClient } from '../rpc';
import { OK } from '../requests';
import {
  AvailableReleaseChannels,
  ChangeLogList,
  ReleaseChannel,
  UpdateChannel,
  UpdateInfo, UpgradeProgress
} from "./types";

const SERVICE_NAME = 'UpdateService';

export default class UpdateService {
  constructor(private client: RPCClient) {}

  getAvailableReleaseChannels() {
    return this.client.call<AvailableReleaseChannels>(SERVICE_NAME, 'AvailableReleaseChannels', null);
  }

  getReleaseChannel() {
    return this.client.call<UpdateChannel>(SERVICE_NAME, 'GetReleaseChannel', null)
  }

  setReleaseChannel(channel: ReleaseChannel) {
    return this.client.call<OK, UpdateChannel>(SERVICE_NAME, 'SetReleaseChannel', {channel})
  }

  checkForUpdates() {
    return this.client.call<UpdateInfo>(SERVICE_NAME, 'CheckForUpdates', null)
  }

  performUpgrade() {
    return this.client.call<OK>(SERVICE_NAME, 'PerformUpgrade', null)
  }

  getUpgradeProgress() {
    return this.client.call<UpgradeProgress>(SERVICE_NAME, 'GetUpgradeProgress', null)
  }

  getChangeLogList() : Promise<ChangeLogList> {
    return fetch('https://api2.hiveos.farm/api/v2/hive/versions?type=asic_hub').then(rsp => {
      if (rsp.status >= 400) {
        throw new Error(rsp.statusText);
      }

      return rsp.json();
    })
  }
}
