import { parseJSON } from "date-fns";

export enum LogLevel {
  Fatal = "fatal",
  Error = "error",
  Warn = "warn",
  Info = "info",
  Debug = "debug"
}

export type Fields = {[key: string]: string|number};

export interface LogRecord {
  time: Date
  level: LogLevel
  tag: string
  message: string
  error?: string
  fields?: Fields
}

const parseLogLine = (line: string, i: number): LogRecord => {
  try {
    const obj = JSON.parse(line.trim());
    const { time, level, tag = "asichub", message, error, ...fields} = obj;
    return {
      time: parseJSON(time),
      level,
      tag,
      message,
      error,
      fields
    };
  } catch (ex) {
    throw new Error(`Parse error at line #${i} "${line}": ${ex}`);
  }
};

export const parseLogLines = (rawText: string) => rawText.split('\n')
  .filter(l => l.length > 0)
  .map(parseLogLine)
  .sort((a, b) => (+a.time) - (+b.time))
  .reverse();
