import { parseJSON } from "date-fns";
import { Response, RPCClient } from "../rpc";
import { OK } from '../requests';
import {
  BackupFileInfo,
  BackupsListResponse,
  FileNameRequest,
  FileNameResponse
} from "./types";

const SERVICE_NAME = "BackupService";

export default class BackupsService {
  constructor(private client: RPCClient) {}

  getBackups(): Promise<BackupFileInfo[]> {
    return this.client.callWithResult<BackupsListResponse>(SERVICE_NAME, "GetBackups", null)
      .then(({backups}) => backups ?? [])
      .then(backups => backups.map(({name, sizeBytes, createdAt}) => ({
        name, sizeBytes, createdAt: parseJSON(createdAt)
      })));
  }

  removeBackup(fileName: string) {
    return this.client.callWithResult<OK, FileNameRequest>(SERVICE_NAME, "RemoveBackup", {fileName});
  }

  createBackup(fileName?: string) {
    return this.client.callWithResult<FileNameResponse>(SERVICE_NAME, "CreateBackup", {fileName});
  }

  restoreFromBackup(fileName: string) {
    return this.client.callWithResult<OK, FileNameRequest>(SERVICE_NAME, "RestoreFromBackup", {fileName});
  }

  getBackupDownloadUrl(fileName: string) {
    return `${this.client.apiEndpoint}/backups/${encodeURIComponent(fileName)}`;
  }

  async importBackup(file: File): Promise<{fileName: string}> {
    const formData = new FormData();
    formData.append('file', file);
    const rsp = await fetch(`${this.client.apiEndpoint}/backups`, {
      method: 'POST',
      body: formData
    });

    let rspBody: Response<{ fileName: string }>;
    const isErrorStatus = rsp.status >= 400;

    try {
      rspBody = await rsp.json();
      if (isErrorStatus) {
        return Promise.reject(rspBody.error);
      }
    } catch (err) {
      if (isErrorStatus) {
        return Promise.reject(new Error(`${rsp.status} ${rsp.statusText}`));
      }
      return Promise.reject(new Error(`Failed to decode JSON response: ${err.message}`));
    }

    return rspBody.result;
  }
}
