export interface Response<T>{
    id: string
    result: T,
    error?: {
        code: number,
        message: string,
        data ?: any
    },
}

const JSON_RPC_VERSION = '2.0';
const uuidv4 = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    // eslint-disable-next-line
    const r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
});

export class RPCClient {
    constructor(private baseURL: string) {}

    get apiEndpoint() {
      return this.baseURL;
    }

  /**
   * Performs call to API and returns full response object.
   *
   * Used only when a whole JSON-RPC response is required.
   *
   * For most cases, please use `RPCClient.callWithResult` instead.
   *
   * @param serviceName Service name
   * @param method  Method
   * @param payload Request payload
   */
    async call<ResT,ReqT=any>(serviceName: string, method: string, payload: ReqT): Promise<Response<ResT>> {
      const {signal}:any = payload || {};  
        const body = {
            id: uuidv4(),
            jsonrpc: JSON_RPC_VERSION,
            method: `${serviceName}.${method}`,
            params: [payload]
        }
        const resp = await fetch(this.baseURL, {
            method: 'POST',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(body),
            signal
        },
        );

        let contents = await resp.json();
        return contents as Response<ResT>
    }

  /**
   * Performs call to API, but returns response payload instead of response object itself.
   *
   * Throws error if response contains an error.
   *
   * @param serviceName Service name
   * @param method  Method
   * @param payload Request payload
   */
  async callWithResult<ResT,ReqT=any>(serviceName: string, method: string, payload: ReqT): Promise<ResT> {
      return this.call<ResT, ReqT>(serviceName, method, payload)
        .then(rsp => {
          if (!!rsp.error) {
            throw rsp.error;
          }
          return rsp.result;
        });
  }
}
