import {getLocalizedParameter} from "../../env";

const defaultMenuItems = {
  'devices': {to: '/', label: 'devices'},
  'events': {to: '/events', label: 'events'},
  'settings': {to: '/settings', label: 'settings'}
}

type MenuItems = {[k: string]: MenuItem}

interface MenuItem {
  label: string,
  to: string,
  external?: boolean
}

export const getMenuItems = (lang: string): MenuItems => {
  const supportUrl = getLocalizedParameter<string>(lang, 'supportUrl');
  if (!supportUrl) return defaultMenuItems;

  return {
    ...defaultMenuItems,
    'support': {
      label: 'help',
      external: true,
      to: supportUrl
    }
  };
};
