import React, {SyntheticEvent} from 'react';

import {
  Typography,
  Space,
  Select,
  Button,
  Alert,
  Skeleton,
  message, Modal
} from "antd";
import { Beforeunload } from 'react-beforeunload';
import {WarningOutlined} from "@ant-design/icons";
import LoadComponent, {LoadState} from "../../core/LoadComponent";
import {ReleaseChannel, UpdateInfo} from "../../../hub/update/types";
import {hasError, updateService} from "../../../hub";
import UpdateProgressModal from "../../core/UpdateProgressModal";
import SettingsSection from "../../form/SettingsSection";
import {withTranslation} from "react-i18next";
import ChangleLogList from './ChangeLog';

const { Text } = Typography;
const { Option } = Select;

interface UpdatePageData {
  availableChannels: ReleaseChannel[]
  selectedChannel: ReleaseChannel
}

interface UpdatePageState extends LoadState<UpdatePageData> {
  showUpdateProgressModal?: boolean
  updateStart?: boolean
  updateCheckLoading?: boolean
  updateCheckError?: any
  updateInfo?: UpdateInfo|null
}

class SoftwareUpdatePage extends LoadComponent<UpdatePageData, UpdatePageState> {
  props: any;
  state: UpdatePageState = {
    updateCheckLoading: true,
    showUpdateProgressModal: false
  };

  get t() {
    return this.props.t;
  }

  onChannelChange(selectedChannel: ReleaseChannel) {
    const { t } = this.props;
    const data = {...this.state.data, selectedChannel} as UpdatePageData;
    this.setState({data});

    updateService.setReleaseChannel(selectedChannel)
      .then(rsp => {
        if (hasError(rsp)) {
          return Promise.reject(rsp.error);
        }
        message.success(t('releaseChannel.changeSuccessMessage'));
      })
      .catch(err => {
        message.error(t('releaseChannel.changeFailedMessage', err));
      });
  }

  async getPageData() {
    try {
      const available = await updateService.getAvailableReleaseChannels()
      const chanResponse = await updateService.getReleaseChannel()
      if (hasError(chanResponse)) {
        this.setLoadError(chanResponse.error);
        return;
      }

      this.setDataLoaded({
        availableChannels: available.result.channels,
        selectedChannel: chanResponse.result.channel,
      })
    } catch (err) {
      this.setLoadError(err)
    }
  }

  checkUpdates() {
    this.setState({updateCheckLoading: true, updateInfo: null});
    updateService.checkForUpdates().then(rsp => {
      if (hasError(rsp)) {
        return Promise.reject(rsp.error);
      }
      this.setState({
        updateCheckLoading: false,
        updateInfo: rsp.result,
        updateCheckError: null,
      })
    }).catch(err => {
      this.setState({updateCheckLoading: false, updateCheckError: err})
    })
  }

  showUpdateError(err) {
    const { t } = this.props;
    this.setState({updateStart: false, showUpdateProgressModal: false});
    Modal.error({
      title: t('newUpdates.updateErrorMessage'),
      content: err.message || err
    });
  }

  onUpdateFinish() {
    this.setState({updateStart: false, showUpdateProgressModal: false});
    this.checkUpdates();
  }

  onBeforeUnload(e: SyntheticEvent) {
    if (this.state.updateStart) {
      e.preventDefault();
    }
  }

  onInstallUpdateClick() {
    const { t } = this.props;
    const { updateInfo } = this.state;
    if (!updateInfo?.otaSupported) {
      Modal.confirm({
        title: t('newUpdates.manualInstallPrompt'),
        width: '800px',
        okText: t('actions.manualInstall'),
        cancelButtonProps: {
          type: 'text'
        },
        icon: <WarningOutlined />,
        content: (
          <Space direction="vertical">
            <Typography.Text>
              {t('newUpdates.manualInstallMessage')}
            </Typography.Text>
            <Typography.Link href={updateInfo?.package?.artifact.url} target="_blank">
              {updateInfo?.package?.artifact.url}
            </Typography.Link>
          </Space>
        ),
        onOk: () => window.open(updateInfo?.package?.artifact.url),
      })
      return;
    }

    this.setState({updateStart: true});
    updateService.performUpgrade()
      .then(rsp => {
        if (hasError(rsp)) {
          return Promise.reject(rsp.error)
        }

        this.setState({showUpdateProgressModal: true});
      })
      .catch(err => this.showUpdateError(err));
  }

  componentDidMount() {
    this.getPageData();
    this.checkUpdates();
  }

  getUpdateBanner() {
    const { t } = this.props;
    const { updateCheckError, updateInfo } = this.state;

    if (updateCheckError) {
      return <Alert
        message={t('newUpdates.updateCheckError')}
        description={updateCheckError.message || updateCheckError}
        type="error"
        showIcon
      />
    }

    if (!updateInfo) {
      return null;
    }

    if (updateInfo.package) {
      const {version, type} = updateInfo.package;
      return <Alert
        message={t('newUpdates.updatesAvailableMessage')}
        description={t('newUpdates.updateDescriptionMessage', {version, type})}
        type="warning"
        showIcon
      />
    }

    return <Alert
      message={t('newUpdates.noUpdatesMessage')}
      description={t('newUpdates.noUpdatesCaption')}
      type="success"
      showIcon
    />
  }

  render() {
    const { showUpdateProgressModal, updateCheckLoading, data, updateInfo } = this.state;
    const { t } = this.props;
    return (
      <div className="SoftwareUpdatePage">
        <SettingsSection
          label={t('releaseChannel.label')}
          description={t('releaseChannel.description')}
        >
          {this.loadError ? (
            <Text type="danger">{t('labels.errorTitle')}: {this.loadError}</Text>
          ) : (
            <Select
              style={{width: '100%'}}
              value={data?.selectedChannel}
              onChange={newVal => this.onChannelChange(newVal)}
              disabled={this.isLoading}
            >
              {data?.availableChannels.map(chan => (
                <Option key={chan} value={chan}>
                  {t(`channels.${chan}`)}
                </Option>
              ))}
            </Select>
          )}
        </SettingsSection>
        <SettingsSection
          label={t('newUpdates.section')}
          orientation="vertical"
          actions={[
            <Button
              type="default"
              key="search"
              disabled={updateCheckLoading}
              onClick={() => this.checkUpdates()}
            >
              {t('actions.search')}
            </Button>,
            <Button
              key="install"
              hidden={!updateInfo || !updateInfo.package}
              type="primary"
              onClick={() => this.onInstallUpdateClick()}
            >
              {t('actions.install')}
            </Button>
          ]}
        >
          {updateCheckLoading ? (
            <Skeleton active paragraph={{ rows: 1 }} />
          ): this.getUpdateBanner()}
        </SettingsSection>
        <SettingsSection 
          label={t('newUpdates.changeLog')}
          orientation="vertical">
            <ChangleLogList/>
        </SettingsSection>
        <UpdateProgressModal
          visible={showUpdateProgressModal}
          onSuccess={() => this.onUpdateFinish()}
          onError={err => this.showUpdateError(err)}
        />
        <Beforeunload onBeforeunload={e => this.onBeforeUnload(e)}/>
      </div>
    )
  }
}

export default withTranslation('softwareUpdate')(SoftwareUpdatePage);
