import React from 'react';
import {Checkbox, Table, Tooltip, Typography} from 'antd';
import {DeviceScanInfo} from "../../hub";
import {brandName} from '../../env';
import {shouldOmitDevice} from "../../types/devices";
import './ScanResultsList.css';
import {TableRowSelection} from "antd/lib/table/interface";
import {useTranslation} from "react-i18next";

interface Props {
  isLoading?: boolean,
  readonly?: boolean
  devices: DeviceScanInfo[]
  selectedKeys?: number[]
  onSelectionChange?: (selectedIndexes: number[]) => void
}

const getCheckboxProps = (d: DeviceScanInfo) => ({
  disabled: shouldOmitDevice(d),
  name: d.ip
})

const ScanResultsList: React.FC<Props> = ({isLoading, devices, selectedKeys, readonly, onSelectionChange}) => {
  const { t } = useTranslation('devicesPage');

  const columns = [
    {
      title: t('columnNames.ipAddr'),
      dataIndex: 'ip',
      render: v => (
        <Typography.Link
          className="text-monospace"
          href={`//${v}`}
          target="_blank">
          {v}
        </Typography.Link>
      ),
    },
    {
      title: t('columnNames.minerType'),
      dataIndex: 'type',
      render: v => (
        <b>{v}</b>
      )
    },
    {
      title: t('columnNames.macAddr'),
      dataIndex: 'mac',
      render: v => (
        <span className="text-monospace">{v.toUpperCase()}</span>
      )
    },
  ];

  const renderDeviceCell = (checked: boolean, record: DeviceScanInfo, index: number, originNode: React.ReactNode) => {
    if (!shouldOmitDevice(record)) {
      return originNode;
    }

    const tooltipMsg = t(record.hasHiveOS ?
      'scanner.managedDeviceError' : 'scanner.duplicateDeviceError',
      { brandName }
    );

    return (
      <Tooltip title={tooltipMsg}>
        <Checkbox disabled={true} checked={false} />
      </Tooltip>
    );
  };

  // Use row selection only if list is not readonly.
  // Unfortunately, <Table> doesn't accept null, but undefined as default value.
  const rowSelection: TableRowSelection<any> | undefined = !readonly ? {
    type: 'checkbox',
    onChange: onSelectionChange as any, // TODO: fix type signatures
    selectedRowKeys: selectedKeys,
    getCheckboxProps,
    renderCell: renderDeviceCell
  } : undefined;

  return (
    <Table
      columns={columns}
      rowKey={(_, i) => i as number}
      loading={isLoading}
      dataSource={devices}
      size="small"
      rowSelection={rowSelection}
      pagination={false}
    />
  )
}

export default ScanResultsList;
