// 'branding' is an import alias to whitelabel branding directory.
// See craco.config.js for more info.

const brandingConfig: BrandingConfig = require('branding/branding.json');

/**
 * BrandingConfig represents custom whitelabel config (branding.json).
 */
export interface BrandingConfig {
  favicon: string
  logo: string
  brandName: string
  dashboardUrl: string
  supportUrl?: string
  overrides?: {
    /**
     * Custom title in page header.
     */
    headerTitle?: string

    /**
     * Custom portal name term. Usually referred to custom Hiveon OS branding.
     */
    portalName?: string
  },
  /**
   * Locale-dependent values
   */
  localeConfig?: {[lang: string]: LocaleValues}
}

interface LocaleValues {
  /**
   * Dashboard URL for different locale
   */
  supportUrl?: string
}

/**
 * Returns localized parameter from branding config.
 * If localized value doesn't exists - returns fallback non-localized value.
 *
 * @param key
 */
export const getLocalizedParameter = <T = any>(lang: string, key: keyof BrandingConfig): T | null => {
  if (brandingConfig.localeConfig?.[lang]?.[key]) {
    return brandingConfig.localeConfig?.[lang][key] as T;
  }

  if (brandingConfig[key]) {
    return brandingConfig[key] as T;
  }

  return null;
};

/**
 * Checks if frontend is running in development mode
 */
export const isDevelopment = () => (
  process?.env?.REACT_APP_ENV === 'development'
);

const {
  favicon, logo, brandName, dashboardUrl, supportUrl, overrides, localeConfig
} = brandingConfig;
export const logoUrl = require(`branding/${logo}`);
export const faviconUrl = require(`branding/${favicon}`);
export const productTitle = overrides?.headerTitle ?? `${brandName} ASIC Hub`;
export const portalName = overrides?.portalName ?? brandName;
export {brandName, dashboardUrl, supportUrl, localeConfig};
