import React from 'react';

export interface LoadState<T> {
  loading?: boolean
  error?: any
  data?: T
}

type BaseProps = React.HTMLAttributes<HTMLDivElement>;

export default class LoadComponent<T=any, S extends LoadState<T> = LoadState<T>, P = BaseProps> extends React.Component<P, S> {
  protected setLoadState(loading: boolean, error?: any) {
    this.setState({loading, error})
  }

  protected get isLoading() {
    const { loading } = this.state;
    return !!loading;
  }

  protected set isLoading(loading: boolean) {
    this.setState({loading});
  }

  protected get loadFailed() {
    const { loading, error } = this.state;
    return !loading && error;
  }

  protected get loadSuccess() {
    const { loading, error } = this.state;
    return !loading && !error;
  }

  protected get loadError() {
    const { error } = this.state;
    return error?.message || error;
  }

  protected setLoading() {
    this.setState({loading: true})
  }

  protected setLoaded() {
    this.setLoadState(false, null)
  }

  protected setDataLoaded(data: T) {
    this.setState({loading: false, error: null, data})
  }

  protected setLoadError(err: any) {
    this.setLoadState(false, err)
  }
}
