import React, {FC, useEffect, useState} from 'react';
import {Button, Form, Input, Modal} from 'antd';
import type {DeviceSummary} from "../../hub";
import {validateIP} from "../../util/validate";
import {devicesService} from "../../hub";
import {useTranslation} from "react-i18next";

interface EditDeviceModalProps {
  visible: boolean
  device?: DeviceSummary
  onCancel: () => void
  onResult: (error?: {message: string}) => void
}

const EditDeviceModal: FC<EditDeviceModalProps> = ({visible, device, onCancel, onResult}) => {
  const { t } = useTranslation('devicesPage');
  const [isLoading, setLoading] = useState(false);
  const [form] = Form.useForm();
  const title = device ? t('itemEditor.title', device) : null;

  useEffect(() => {
    // clean form on close
    if (!visible) form.resetFields();
    if (!device) return;
    const {ip, username, password} = device;
    form.setFieldsValue({ip, username, password});
  }, [visible, device, form]);

  const onFinish = (values) => {
    const {id} = device as DeviceSummary;
    setLoading(true);

    // replace empty credential values ("") with null
    const {username, password} = values;
    const req = {
      ...values,
      username: username?.length > 0 ? username : null,
      password: password?.length > 0 ? password : null,
    }

    devicesService.updateDeviceById(id, req)
      .then(rsp => {
        setLoading(false);
        onResult(rsp.error);
      }).catch(err => {
        setLoading(false);
        onResult(err);
      });
  };

  return <Modal
    title={title}
    visible={visible}
    centered={true}
    closable={!isLoading}
    maskClosable={!isLoading}
    onCancel={onCancel}
    width={480}
    footer={
      !device ? null : (
        <>
          <Button
            type="text"
            onClick={onCancel}
            disabled={isLoading}
          >
            {t('actions.cancel')}
          </Button>
          <Button
            type="primary"
            loading={isLoading}
            onClick={() => form.submit()}
          >
            {t('actions.save')}
          </Button>
        </>
      )
    }
  >
    <Form
      form={form}
      name="device-edit"
      onFinish={onFinish}
      layout="vertical"
      aria-autocomplete="none"
      autoComplete="none"
    >
      <Form.Item
        label={t('forms.ip.label')}
        name="ip"
        rules={[
          {validator: (_, val) => {
            if (!validateIP(val)) {
              return Promise.reject(t('forms.ip.validationError'));
            }
            return Promise.resolve();
          }}
        ]}
      >
        <Input
          placeholder={t('forms.ip.placeholder')}
          autoComplete="none"
          disabled={isLoading}
        />
      </Form.Item>
      <Form.Item
        label={t('forms.username.label')}
        name="username"
      >
        <Input
          placeholder={t('forms.username.placeholder')}
          autoComplete="none"
          disabled={isLoading}
        />
      </Form.Item>
      <Form.Item
        label={t('forms.password.label')}
        name="password"
      >
        <Input.Password
          placeholder={t('forms.password.placeholder')}
          autoComplete="none"
          disabled={isLoading}
        />
      </Form.Item>
    </Form>
  </Modal>
}

export default EditDeviceModal;
