import React from 'react';
import './PageActionsFooter.less';

const PAGE_ACTIONS_CLASS = 'PageActionsFooter';

interface PageActionsFooterProps {
  margin?: string|number;
  gravity?: 'left' | 'right' | 'center';
  visible?: boolean;
}

const PageActionsFooter: React.FC<PageActionsFooterProps> = props => {
  const {visible, gravity, children, margin} = props;
  if (!visible) {
    return null;
  }

  return (
    <div
      className={`${PAGE_ACTIONS_CLASS} ${PAGE_ACTIONS_CLASS}--${gravity}`}
      style={{marginTop: margin, marginBottom: margin}}
    >
      <div className="PageActionsFooter__container">
        {children}
      </div>
    </div>
  )
}

PageActionsFooter.defaultProps = {
  visible: true,
  gravity: 'right',
  margin: 36
}

export default PageActionsFooter;
