import React, {FC, useState} from 'react';
import './SearchByInput.less';
import {Select, Input, Button} from "antd";
import {useTranslation} from "react-i18next";

export interface SearchQuery {
  key: string
  query: string
}

interface SearchByProps extends React.HTMLAttributes<HTMLDivElement> {
  disabled?: boolean
  options: {[k: string]: string}
  i18nNamespace?: string | string[]
  value?: SearchQuery | null
  placeholderFormat?: (key: string) => string
  onValueChange: (value: SearchQuery|null) => void
}

const SearchByInput: FC<SearchByProps> = ({options, value, disabled, onValueChange, style, i18nNamespace, placeholderFormat}) => {
  const { t } = useTranslation(i18nNamespace);
  const [query, setQuery] = useState<string>(value?.query ?? '');
  const [key, setKey] = useState<string>(value?.key ?? Object.keys(options)[0]);

  return (
    <div className="SearchByInput" style={style}>
      <Input.Group compact style={{width: '100%', display: 'flex'}}>
        <Select
          className="SearchByInput__key"
          value={key}
          disabled={disabled}
          onChange={k => {
            setKey(k)

            // Revert search state value if selected key is same as passed
            setQuery(value?.key === k ? value.query : '');
          }}
        >
          {Object.entries(options).map(([k,v]) => (
            <Select.Option key={k} value={k}>{t(v)}</Select.Option>
          ))}
        </Select>
        <Input
          value={query}
          disabled={disabled}
          onChange={e => setQuery(e.target.value)}
          placeholder={t('search.placeholder', {
            criteria: placeholderFormat?.(key) ?? options[key]
          })}
          onPressEnter={() => {
            if (!query.length) {
              return;
            }
            onValueChange({key, query});
          }}
          suffix={
            <Button
              type="link"
              size="small"
              className="SearchByInput__btn SearchByInput__btn--reset"
              hidden={!value}
              onClick={() => {
                setQuery('');
                onValueChange(null);
              }}
            >
              {t('search.actions.reset')}
            </Button>
          }
        />
        <Button
          disabled={disabled || !query.length}
          onClick={() => {
            onValueChange(query.length ? {key, query} : null);
          }}
        >
          {t('search.actions.search')}
        </Button>
      </Input.Group>
    </div>
  )
};

export default SearchByInput;
