import React from 'react';

import {Alert, Button} from 'antd';
import {useTranslation} from "react-i18next";

interface Props {
  visible?: boolean
  itemsCount?: number
  onAction: () => void
}

const UnknownDevicesNotification: React.FC<Props> = ({visible, itemsCount, onAction}) => {
  const { t } = useTranslation('devicesPage');
  if (!visible) {
    return null;
  }

  return (
    <Alert
      type="warning"
      message={t('unknownDevice.notification', {count: itemsCount})}
      showIcon={true}
      action={
        <Button size="small" type="ghost" onClick={onAction}>
          {t('actions.inspect')}
        </Button>
      }
    />
  );
};

export default UnknownDevicesNotification;
