import React from 'react';
import {Skeleton} from "antd";
import './SettingsSection.less';
import './SettingsSectionPlaceholder.less';

interface Props {
  active?: boolean
  orientation?: 'horizontal' | 'vertical'
  rows?: number
}

const SettingsSectionPlaceholder: React.FC<Props> = ({active, orientation, rows}) => (
  <section className={`SettingsSection SettingsSection--${orientation}`}>
    <div className="SettingsSection__info">
      <Skeleton active={active} paragraph={false} title={{className: 'SettingsSection__label', width: 200}}/>
      {rows && (

        <Skeleton active={active} title={false} paragraph={{
          className: 'SettingsSection__description',
          rows
        }}/>
      )}
    </div>
    <div className="SettingsSection__container">
      <div className="SettingsSection__control">
        <Skeleton.Input active={active}/>
      </div>
    </div>
  </section>
);

SettingsSectionPlaceholder.defaultProps = {
  orientation: 'horizontal'
};

export default SettingsSectionPlaceholder;
