/**
 * Worker name source type indicates where ASIC Hub should pull worker name.
 */

export enum WorkerNameSource {
  /**
   * Indicates that Hub should take worker name from Hiveon OS.
   */
  Remote = "remote",

  /**
   * Indicates that Hub should use ASIC's hostname as worker name.
   */
  Hostname = "hostname"
}

/**
 * ConfigurationDelta contains configuration changes (delta) to be applied.
 *
 * @see Configuration
 */
export type ConfigurationDelta = {[K in keyof Configuration]?: Configuration[K]};

export interface Configuration {
  /**
   * Worker name source for ASICs.
   *
   * @see WorkerNameSource
   */
  workerNameSource: WorkerNameSource
}

export interface ServerConfig {
  apiUrl: string
  hiveWebURL: string
  updateServer: string
  tempDir: string
  maxThreads: number
  api: {
    maxIdleConnsPerHost: number
  }
  http: {
    listen: string
    writeTimeout: string
    readTimeout: string
    staticDir: string
    disableCORS: boolean
    denyAccessFromPublicNetworks: boolean
  }
  log: {
    filePath: string
    debug: boolean
    maxFileSize: number
    maxBackups: number
    maxAge: number
    maxTailBufferSize: number
  }
  arp: {
    enableScanner: string
    scanInterval: string
  }
  monitoring: {
    disabled?: boolean
    maxGroupSize?: number
    defaultPingInterval?: string
    statsCollectInterval?: string
    hubHeartbeatInterval?: string
    statsSendInterval?: string
    probeTimeout?: string
    connectTimeout?: string
    queueBufferSize?: string
    bufferFillTimeout?: string
    ignoreMirrorsList?: boolean
    enableBulkStats?: boolean
  }
  localState: {
    db: string
    backupsDir: string
  }
  experimental: {[k: string]: any}
}

export interface ConfigSaveResult {
  manualRestartRequired: boolean
}
