import React, {PureComponent} from "react";
import { InitOptions, i18n } from "i18next";
import {Store} from "redux";
import {State} from "../store/state";
import {Action} from "../store/actions";
import {localeConfig} from "./config";
import {isDevelopment} from "../env";

interface LocaleSyncGateProps {
  store: Store<State, Action>
  localeConfig?: InitOptions
  loading: React.ReactNode
  i18nInstance: i18n,
}

interface LocaleSyncGateState {
  bootstrapped: boolean
}

/**
 * LocaleSyncGate initializes i18next language settings from store.
 */
export default class LocaleSyncGate extends PureComponent<LocaleSyncGateProps, LocaleSyncGateState> {
  static defaultProps = {
    store: null,
    loading: null,
    localeConfig: localeConfig,
  }

  state = {
    bootstrapped: false
  }

  async componentDidMount() {
    if (this.state.bootstrapped) {
      return;
    }

    const { store, localeConfig, i18nInstance } = this.props;
    const { language } = store.getState();
    await i18nInstance.init({
      ...localeConfig,
      lng: language,
      debug: isDevelopment()
    });
    this.setState({bootstrapped: true});
  }

  render(): React.ReactNode {
    return this.state.bootstrapped ? this.props.children : this.props.loading;
  }
}
