import i18n, { InitOptions } from "i18next";
import {initReactI18next} from "react-i18next";
import {fallbackLanguage, languagesList} from "./resources";

export const localeConfig: InitOptions = {
  fallbackLng: fallbackLanguage,
  defaultNS: 'common',
  fallbackNS: 'common',
  supportedLngs: Object.keys(languagesList),
  resources: {
    en: require('./resources/en.json'),
    ru: require('./resources/ru.json'),
    uk: require('./resources/uk.json'),
    zh: require('./resources/zh.json')
  },
  interpolation: {
    // react already safes from xss => https://www.i18next.com/translation-function/interpolation#unescape
    escapeValue: false,
  }
};

export const createI18nInstance = () => i18n
  .use(initReactI18next);
