import React, {useEffect, useState} from 'react';
import { Button, Spin, Result } from 'antd';
import {LoadingOutlined} from "@ant-design/icons";
import HubContainer from "../../core/HubContainer";
import {LogRecord} from "../../../hub/log";
import {useLoadState} from "../../../util/hooks";
import {hubService} from "../../../hub";
import LogEntry from "./LogEntry";
import LogFilter from "./LogFilter";
import './LogViewPage.less'
import {filterRecords, Query} from "./search";
import {useTranslation} from "react-i18next";

const preloadIcon = <LoadingOutlined style={{ fontSize: '10em' }} spin />;

const defaultLimit = 100;
const nextItemsCount = 50;

const LogViewPage: React.FC = () => {
  const { t } = useTranslation('logView');
  const [records, setRecords] = useState<LogRecord[]>([]);
  const [visibleRecords, setVisibleRecords] = useState<LogRecord[]>([]);
  const [loadState, setError, setLoading] = useLoadState(true);
  const [limit, setLimit] = useState(defaultLimit);

  useEffect(() => {
    setLoading(true);
    hubService.getLogRecords().then(records => {
      setLoading(false);
      setRecords(records);
      setVisibleRecords(records);
    }).catch(err => {
      setError(err);
      console.error(err);
    });
    // eslint-disable-next-line
  }, []);

  const onFilter = (filter: Query) => {
    setVisibleRecords(filterRecords(filter, records));
  };

  return (
    <HubContainer>
      {loadState.loading ? (
        <Spin className="LogViewPage__preloader" indicator={preloadIcon} />
      ) : (
        <div className="LogViewPage__container">
          <LogFilter
            onFilter={onFilter}
            onReset={() => setVisibleRecords(records)}
          />
          <div className="LogViewPage__events">
            {visibleRecords.slice(0, limit).map((record, i) => (
              <LogEntry key={i} record={record} />
            ))}
          </div>
          {limit < visibleRecords.length ? (
            <Button
              className="LogViewPage__loadMore"
              onClick={() => setLimit(limit + nextItemsCount)}
            >
              {t('actions.showMore')}
            </Button>
          ) : null}
        </div>
      )}

      {loadState.error ? (
        <Result
          title="Failed to fetch log"
          status="error"
          subTitle={loadState.error?.message || loadState.error}
        />
      ) : null}
    </HubContainer>
  )
};

export default LogViewPage;
