import React, {FC} from 'react';
import {Typography} from "antd";
import './Label.less'

interface LabelProps extends React.HTMLAttributes<HTMLDivElement> {
  disabled?: boolean
}

const getClassName = (props: LabelProps) => {
  const classes = ['Label'];
  if (props.disabled) {
    classes.push('Label--disabled')
  }

  return classes.join(' ')
}

const Label: FC<LabelProps> = (props) => (
  <Typography.Text className={getClassName(props)}>{props.children}</Typography.Text>
);

export default Label;
