import { RPCClient } from './rpc';
import {
  URLConfig,
  ScanRequest,
  ScanResponse,
  SetupCompleteState,
  SetupHubRequest,
  OK, GetInfoResponse,
} from './requests';
import { LogRecord, parseLogLines } from "./log";

const HUB_SERVICE_NAME = 'HubService';

export default class HubService {
  constructor(private client: RPCClient) {}

  get logFileUrl() {
    return `${this.client.apiEndpoint}/log`
  }

  /**
   * Check if ASIC Hub was set up
   */
  isSetupComplete() {
      return this.client.call<SetupCompleteState>(HUB_SERVICE_NAME, 'IsSetupComplete', null);
  }

  /**
   * Performs asic scan and returns list of devices found
   *
   * @param req Request
   */
  scan(req: ScanRequest) {
      return this.client.callWithResult<ScanResponse, ScanRequest>(HUB_SERVICE_NAME, 'Scan', req);
  }

  /**
   * Configure ASIC Hub server
   *
   * @param req Configuration
   */
  setupHub(req: SetupHubRequest) {
      return this.client.callWithResult<OK, SetupHubRequest>(HUB_SERVICE_NAME, 'SetupHub', req);
  }

  /**
   * Returns ASIC Hub status
   */
  getInfo() {
    return this.client.call<GetInfoResponse>(HUB_SERVICE_NAME, 'GetInfo', null);
  }

  getUrlConfig() {
    return this.client.callWithResult<URLConfig>(HUB_SERVICE_NAME, 'GetURLConfig', null);
  }

  startMonitor() {
    return this.client.call<OK>(HUB_SERVICE_NAME, 'StartMonitor', null);
  }

  stopMonitor() {
    return this.client.call<OK>(HUB_SERVICE_NAME, 'StopMonitor', null);
  }

  restartMonitor() {
    return this.client.call<OK>(HUB_SERVICE_NAME, 'RestartMonitor', null);
  }

  getLogRecords(): Promise<LogRecord[]> {
    return fetch(this.logFileUrl).then(rsp => {
      if (rsp.status >= 400) {
        throw new Error(rsp.statusText);
      }

      return rsp.text();
    }).then(parseLogLines);
  }
}
