import { i18n } from "i18next";
import {Action, newChangeLanguageAction} from "./actions";
import {ThunkAction} from "redux-thunk";
import {State} from "./state";

export interface ThunkExtraArgs {
  i18nInstance: i18n
}

/**
 * Creates a new thunk action that changes the UI language and locale.
 *
 * @See /locales/config.ts for available languages
 * @param lang
 */
export const changeLanguageDispatcher = (lang: string): ThunkAction<any, State, ThunkExtraArgs, Action<string>> => (
  (dispatch, getState, {i18nInstance} : { i18nInstance: i18n }) => {
    i18nInstance.changeLanguage(lang).then(() => {
      dispatch(newChangeLanguageAction(lang));
    }).catch(err => {
      console.log('Failed to change language: ', err);
    });
  }
);
