import { groupBy } from 'lodash';
import {
  CIDRTarget,
  IPTarget,
  RangeTarget,
  ScanTarget
} from "../hub/scan-target";
import {ScanRequest} from "../hub/requests";
import {DeviceScanInfo} from "../hub";

export interface CredentialsInputTarget {
  key: number
  item: ScanTarget
}

export const isIpTarget = (t: ScanTarget): t is IPTarget => 'ip' in t;
export const isCidrTarget = (t: ScanTarget): t is CIDRTarget => 'cidr' in t;
export const isRangeTarget = (t: ScanTarget): t is RangeTarget => 'from' in t && 'to' in t;
export const shouldOmitDevice = (d: {hasHiveOS: boolean, exists: boolean}) => d.hasHiveOS || d.exists;

export function getScanTargetLabel(t: ScanTarget): string {
  if (isIpTarget(t)) {
    return t.ip;
  }

  if (isCidrTarget(t)) {
    return t.cidr;
  }

  if (isRangeTarget(t)) {
    return `${t.from} - ${t.to}`;
  }

  return '';
}

export function scanTargetsToScanRequest(targets: ScanTarget[]): ScanRequest {
  return groupBy(targets, (v): keyof ScanRequest => {
    if (isIpTarget(v)) {
      return 'ips'
    }

    if (isCidrTarget(v)) {
      return 'cidrs';
    }

    if (isRangeTarget(v)) {
      return 'ranges';
    }

    throw new Error(`unknown target type: ${JSON.stringify(v)}`);
  });
}

export const scanInfoToRegistrations = (farmHash: string, items: DeviceScanInfo[]) =>
  items.filter(d => !shouldOmitDevice(d)).map(item => {
    const {ip, kind, credentials} = item;
    return {ip, kind, farmHash, credentials};
  });
