import React, {
  useEffect,
  useCallback,
  useState,
  ClipboardEventHandler
} from 'react';
import clsx from 'clsx';
import './ItemsListInput.less';

const KEY_BACKSPACE = 'Backspace';
const DELIMITER_COMMA = ',';
const DELIMITER_SPACE = ' ';
const VALUE_DELIMITERS = new Set([DELIMITER_SPACE, DELIMITER_COMMA]);

export interface ItemsListInputProps {
  /**
   * Unique input ID
   */
  id?: string

  /**
   * Custom class name
   */
  className?: string

  /**
   * Input name
   */
  name?: string;

  /**
   * Items list as control value.
   */
  value?: string[]

  /**
   * Apply monospace font option.
   */
  monospace?: boolean

  /**
   * Disables the control.
   */
  disabled?: boolean

  /**
   * Placeholder text.
   */
  placeholder?: string

  /**
   * Callback to call on item collection change.
   *
   * Called only when a new valid item was added or removed.
   * @param values
   */
  onChange?: (values?: string[]) => void

  /**
   * Blur event handler
   * @param e
   */
  onBlur?: (e: React.FocusEvent<HTMLInputElement>) => void

  /**
   * Input item value validator.
   * @param value
   */
  validator?: (value: string) => boolean
}

/**
 * ItemsListInput is a comma or space separated items list.
 */
const ItemsListInput: React.FC<ItemsListInputProps> = ({
  id,
  name,
  className,
  monospace,
  value,
  disabled,
  onChange,
  onBlur,
  validator,
  placeholder
}) => {
  const [isFocused, setFocused] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [isInvalid, setInvalid] = useState(false);
  const [isDirty, setDirty] = useState(false);

  const emitChangeEvent = (newElements: string[]) => {
    const changes = (Array.isArray(value) && value?.length) ?
      [...value, ...newElements] : newElements;
    // Remove duplicates before emit
    const uniqueElements = Array.from(new Set(changes));
    if (uniqueElements.length) {
      onChange?.(uniqueElements);
    }
  };

  const onControlBlur = () => {
    setFocused(false);
    if (!inputValue?.length) {
      return;
    }

    // Append a value in input if it's valid
    const valid = validator?.(inputValue) ?? true;
    if (!valid) {
      return;
    }

    emitChangeEvent([inputValue]);
    setInputValue('');
  };

  const popLastItem = () => {
    if (inputValue.length || !value?.length) {
      return;
    }

    const newValues = value.slice();
    const lastElement = newValues.pop()!;
    setInputValue(lastElement);
    onChange?.(newValues);
  };

  const removeItemAtIndex = useCallback(index => {
    onChange?.(value!.filter((_, i) => i !== index));
  }, [onChange, value]);

  const handlePaste: ClipboardEventHandler<HTMLInputElement> = e => {
    e.preventDefault();
    const text = e.clipboardData.getData('text');
    if (!text?.length) {
      return;
    }

    // Chars split behavior should be synchronized with VALUE_DELIMITERS value.
    const elements = text.split(DELIMITER_COMMA)
      .map(v => v.split(DELIMITER_SPACE))
      .flat()
      .filter(v => v.length);

    if (!elements.length) {
      return;
    }

    // Select valid elements and stop at first invalid element.
    // The rest of invalid string goes to the input.
    const validIndexes = elements.map(v => validator?.(v) ?? true);
    let firstInvalidElementIndex = validIndexes.findIndex(valid => !valid);
    switch (firstInvalidElementIndex) {
      case -1:
        emitChangeEvent(elements);
        return;
      case 0:
        setInputValue(text);
        return;
      default:
        break;
    }

    const validElements = elements.slice(0, firstInvalidElementIndex);
    const restRawValue = elements.slice(firstInvalidElementIndex).join(', ');
    setInputValue(restRawValue);
    emitChangeEvent(validElements);
  };

  useEffect(() => {
    setDirty(!!inputValue?.length);
    if (!inputValue?.length) {
      setInvalid(false);
      return;
    }

    // Check if string contains a delimiter and skip if string is unterminated.
    const lastChar = inputValue.charAt(inputValue.length - 1);
    if (!VALUE_DELIMITERS.has(lastChar)) {
      setInvalid(validator ? !validator?.(inputValue) : false);
      return;
    }

    // Validate a value
    const valueWithoutSuffix = inputValue.substring(0, inputValue.length - 1).trim();
    let ok = validator?.(valueWithoutSuffix) ?? true;
    setInvalid(!ok);
    if (!ok) {
      return;
    }

    if (value?.includes(valueWithoutSuffix)) {
      return;
    }

    setInputValue('');
    onChange?.(value ? [...value, valueWithoutSuffix] : [valueWithoutSuffix]);
  }, [inputValue, setInvalid, setInputValue, onChange, validator, value]);

  return (
    <label
      htmlFor={id ?? name}
      className={clsx('AddressInputList', className, {
        'AddressInputList--focused': isFocused,
        'AddressInputList--invalid': isDirty && isInvalid,
        'AddressInputList--dirty': isDirty,
        'AddressInputList--filled': !!value?.length,
        'AddressInputList--monospace': monospace,
      })}
    >
      <ul className="AddressInputList__items">
        {value?.map((val, i) => (
          <li className="AddressInputList__item" key={i}>
            <span className="AddressInputList__item__value">{val}</span>
            <button
              type="button"
              className="AddressInputList__item__remove"
              disabled={disabled}
              onClick={() => removeItemAtIndex(i)}
            >
              &times;
            </button>
          </li>
        ))}
      </ul>
      <input
        id={id ?? name}
        type="text"
        name={name}
        className="AddressInputList__input"
        disabled={disabled}
        value={inputValue}
        placeholder={value?.length ? '' : placeholder}
        onFocus={() => setFocused(true)}
        onBlur={e => {
          onControlBlur();
          onBlur?.(e);
        }}
        onChange={({target: {value}}) => setInputValue(value)}
        onPaste={handlePaste}
        onKeyDown={({key}) => {
          if (key === KEY_BACKSPACE) {
            popLastItem();
          }
        }}
      />
    </label>
  )
};

export default ItemsListInput;
