import React, {FC, useEffect} from 'react';
import {Button, Form, Input, Modal, Space, Typography} from 'antd';
import {CredentialsInputTarget, getScanTargetLabel} from '../../types/devices';
import {Credentials} from "../../hub/scan-target";
import {useTranslation} from "react-i18next";

interface Props {
  isVisible: boolean
  target?: CredentialsInputTarget | null
  value?: Credentials | null,
  onCancel: () => void,
  onSave: (t: CredentialsInputTarget, creds: Credentials) => void,
  onRemove: (t: CredentialsInputTarget) => void,
}

const CredentialsInputModal: FC<Props> = ({isVisible, value, target, onCancel, onSave, onRemove}) => {
  const { t } = useTranslation('devicesPage');
  const [form] = Form.useForm();
  const modalTitle = target ? t('credentialsEditor.title', { target: getScanTargetLabel(target.item) }) : '';

  useEffect(() => {
    // clean form on close
    if (!isVisible) form.resetFields();
    if (!value) return;
    const {username, password} = value;
    form.setFieldsValue({
      username, password
    })
  }, [isVisible, value, form])

  const onFinish = values => {
    if (!target) return;
    const {username, password} = values;
    onSave(target, {username, password});
  }

  return <Modal
    visible={isVisible}
    title={modalTitle}
    wrapClassName='CredentialsInputModal'
    centered={true}
    closable={true}
    maskClosable={true}
    onCancel={onCancel}
    width={550}
    footer={
      !target ? null : (
        <>
          <Button type="default" onClick={onCancel}>
            {t('actions.cancel')}
          </Button>
          <Button type="primary" onClick={() => form.submit()}>
            {t('actions.save')}
          </Button>
          <Button
            style={{float: 'left'}}
            onClick={() => onRemove(target)}
            disabled={!value}
            danger
          >
            {t('credentialsEditor.actions.reset')}
          </Button>
        </>
      )
    }
  >
    <Space>
      <Typography.Paragraph>
        {t('credentialsEditor.section1')}<br/>
        {t('credentialsEditor.section2')}
      </Typography.Paragraph>
    </Space>
    <Form
      form={form}
      name="asic-credentials"
      onFinish={onFinish}
      layout='vertical'
    >
      <Form.Item
        label={t('forms.username.label')}
        name="username"
        rules={[{required: true, message: t('forms.username.validationError')}]}
      >
        <Input autoComplete="off" placeholder={t('forms.username.placeholder')}/>
      </Form.Item>
      <Form.Item
        label={t('forms.password.label')}
        name="password"
        rules={[{required: true, message: t('forms.password.validationError')}]}
      >
        <Input.Password autoComplete="off" placeholder={t('forms.password.placeholder')}/>
      </Form.Item>
    </Form>
  </Modal>
}

export default CredentialsInputModal;
