import React, {FC} from 'react';
import {
  Space,
  Table,
  Button,
  Result,
  Typography, Popover,
} from 'antd';
import type {PaginationProps} from "antd/lib/pagination";
import type {ColumnsType} from "antd/lib/table";
import type {TableLocale, TablePaginationConfig, SorterResult } from "antd/lib/table/interface";
import { DeleteFilled, EditOutlined, WarningOutlined } from "@ant-design/icons";
import {
  DEFAULT_HIVE_URL, DeviceKey,
  DeviceSummary,
  formatWorkerUrl, Sorting,
} from "../../hub";
import "./DevicesList.less"
import {useTranslation} from "react-i18next";
import {TFunction} from "i18next";

const { Link } = Typography;

const CLASS_ROW_GENERIC = 'DevicesList__row';
const CLASS_ROW_OFFLINE = `${CLASS_ROW_GENERIC} DevicesList__row--offline`;

const WorkerOfflinePopover = () => {
  const { t } = useTranslation('devicesPage')
  return (
    <Popover
      title={t('messages.asicOfflineTitle')}
      placement="left"
      content={<>
        {t('messages.asicOfflineMessage1')}<br />
        {t('messages.asicOfflineMessage2')}
      </>}
    >
      <WarningOutlined />
    </Popover>
  );
};

const getTableColumns = (t: TFunction, hiveBaseUrl: string, onDelete: (i: DeviceSummary) => void, onEdit: (i: DeviceSummary) => void, offlineIds?: Set<number>) : ColumnsType<DeviceSummary> => [
  {
    key: 'ip',
    title: t('columnNames.ipAddr'),
    dataIndex: 'ip',
    width: '120px',
    sorter: true,
    render: v => (
      <Link
        className="text-monospace"
        href={`http://${v}`}
        target="_blank">
        {v}
      </Link>
    )
  },
  {
    title: t('columnNames.workerName'),
    key: 'workerName',
    sorter: true,
    dataIndex: 'workerName',
    render: (workerName: string, v: DeviceSummary) => (
      <Link
        href={formatWorkerUrl(hiveBaseUrl, v.farmId, v.rigId)}
        target="_blank">
        <b className="text-default text-link">{workerName}</b>
      </Link>
    )
  },
  {
    key: 'type',
    title: t('columnNames.minerType'),
    dataIndex: 'type',
    sorter: true,
  },
  {
    key: 'mac',
    title: t('columnNames.macAddr'),
    dataIndex: 'mac',
    sorter: true,
    render: v => (
      <span className="text-monospace">{v.toUpperCase()}</span>
    )
  },
  {
    title: '',
    key: 'notifications',
    width: '33px',
    render: (item: DeviceSummary) => (offlineIds?.has(item.id) ? <WorkerOfflinePopover /> : null)
  },
  {
    title: '',
    key: 'action',
    onCell: () => ({className:'DevicesList__cell--action'}),
    render: item => <Space size="small">
      <Button
        size="small"
        type="text"
        title={t('actions.editDevice')}
        className="btn-icon"
        icon={<EditOutlined />}
        onClick={() => onEdit(item)}
      />
      <Button
        size="small"
        type="text"
        title={t('actions.removeDevice')}
        className="btn-icon btn-icon-danger"
        icon={<DeleteFilled />}
        onClick={() => onDelete(item)}
      />
    </Space>
  }
];

const getOffset = (pagination) => {
  const {pageSize, current} = pagination;
  if (current === 1) return 0;
  return (current - 1) * pageSize;
}

const DEFAULT_PAGE_OPTIONS: PaginationProps = {
  pageSizeOptions: ['10', '25', '50', '100', '250', '500', '1000', '2000']
}

export interface ViewChangeEvent {
  pageSize: number
  currentPage: number
  offset: number
  sorting?: Sorting | null
}

interface DevicesListProps {
  error?: any
  hiveBaseUrl?: string
  loading?: boolean
  devices: DeviceSummary[]
  offlineIds?: Set<number>
  pageSize: number
  currentPage: number
  totalItems: number
  selectedIds?: number[]
  locale?: TableLocale
  onRetry: () => void
  onSelect: (ids: number[]) => void
  onChange: (p: ViewChangeEvent) => void
  onRemove: (i: DeviceSummary) => void
  onEdit: (i: DeviceSummary) => void
}

export const DevicesList: FC<DevicesListProps> = props => {
  const { t } = useTranslation();
  const {
    error, pageSize, currentPage, offlineIds,
    totalItems, devices, loading, onRemove, onEdit
  } = props;

  let baseUrl = props.hiveBaseUrl || DEFAULT_HIVE_URL;
  if (error) {
    return (
      <Result
        status="error"
        title={t('labels.errorTitle')}
        subTitle={error}
        extra={[
          <Button key="retry" onClick={props.onRetry} type="primary">
            {t('actions.retry')}
          </Button>,
        ]}
      />
    )
  }

  const pagination: TablePaginationConfig = {
    ...DEFAULT_PAGE_OPTIONS,
    current: currentPage,
    pageSize: pageSize,
    showSizeChanger: true,
    total: totalItems,
    position: ['bottomRight']
  }
  const getRowClass = (r: DeviceSummary) => (
    offlineIds?.has(r.id) ? CLASS_ROW_OFFLINE : CLASS_ROW_GENERIC
  );

  return <Table
    size="small"
    className="DevicesList__table"
    columns={getTableColumns(t, baseUrl, onRemove, onEdit, offlineIds)}
    rowKey={i => i.id}
    dataSource={devices}
    loading={loading}
    pagination={pagination}
    locale={props.locale}
    rowClassName={getRowClass}
    rowSelection={{
      type: 'checkbox',
      onChange: keys => props.onSelect(keys as number[]),
      selectedRowKeys: props.selectedIds
    }}
    onChange={(pagination, filters, sorter) => {
      const offset = getOffset(pagination);
      const {current} = pagination;

      const {order, columnKey} = sorter as SorterResult<DeviceSummary>
      props.onChange({
        offset,
        pageSize: pagination.pageSize ?? pageSize,
        currentPage: current ?? 1,
        sorting: order ? {
          key: (columnKey as unknown) as DeviceKey,
          order: order === 'ascend' ? 1 : -1
        } : null
      });
    }}
  />
}
