import React, { useEffect, useState } from 'react';
import { Modal, Button, Input, Col, Row, Typography, message } from "antd";
import { ExclamationCircleOutlined } from "@ant-design/icons";

import { BackupFileInfo, backupsService } from "../../../hub";
import { useLoadState } from "../../../util/hooks";
import { validateFileName } from "../../../util/validate";
import SettingsSection from "../../form/SettingsSection";
import BackupsList from "./BackupsList";
import ImportBackupSection from "./backup/ImportBackupSection";
import { useTranslation } from "react-i18next";

const emptyList = [];
const initialFileNameState = { valid: true, value: '' };

const fieldErrorSuffix = (val: string, valid: boolean) => {
  if (!val || valid) {
    return <span />
  }

  return <ExclamationCircleOutlined style={{ 'color': '#f00' }} />
};

const BackupsPage = () => {
  const { t } = useTranslation('backups');
  const [loadState, setError, setLoading] = useLoadState(false);
  const [fileNameState, setFileNameState] = useState(initialFileNameState);
  const [files, setFiles] = useState<BackupFileInfo[]>(emptyList);
  const [isBusy, setIsBusy] = useState(false);
  const { valid, value } = fileNameState;

  const refreshBackupsList = () => {
    setLoading(true);
    backupsService.getBackups().then(files => {
      setFiles(files);
      setLoading(false);
    }).catch(err => {
      setError(err?.message ?? err);
    })
  };

  const createBackup = () => {
    setIsBusy(true);
    backupsService.createBackup(value)
      .then(({ fileName }) => {
        message.success(t('messages.backupSuccess', { fileName }));
        setIsBusy(false);
        setFileNameState(initialFileNameState);
        refreshBackupsList();
      }).catch(err => {
        message.error(err?.message ?? err);
        setIsBusy(false);
      });
  };

  const onItemDelete = (fileName: string) => {
    Modal.confirm({
      title: t('labels.removePromptTitle', { fileName }),
      content: t('labels.removePromptMessage'),
      okButtonProps: { danger: true },
      cancelButtonProps: { type: 'text' },
      width: "480px",
      onOk: async () => {
        try {
          setIsBusy(true);
          await backupsService.removeBackup(fileName);
          message.success(t('messages.removeSuccess', { fileName }));
        } catch (err) {
          message.error(t('messages.removeFailed', { fileName, message: err?.message ?? err }));
        }

        setIsBusy(false);
        refreshBackupsList();
      }
    });
  }

  const onItemRestore = (fileName: string) => {
    Modal.confirm({
      title: t('labels.restorePromptTitle', { fileName }),
      content: t('labels.restorePromptMessage'),
      okButtonProps: { danger: true },
      cancelButtonProps: { type: 'text' },
      width: "640px",
      onOk: async () => {
        try {
          setIsBusy(true);
          await backupsService.restoreFromBackup(fileName);
          message.success(t('messages.restoreSuccess', { fileName }));
        } catch (err) {
          message.error(err?.message ?? err);
        }
        setIsBusy(false);
      }
    })
  };

  useEffect(() => {
    setLoading(true);
    backupsService.getBackups().then(files => {
      setFiles(files);
      setLoading(false);
    }).catch(err => {
      setError(err?.message ?? err);
    })
    // eslint-disable-next-line
  }, []);

  return (
    <>
      <SettingsSection
        label={t('newBackup.label')}
        description={
          <>
            <p>
              {t('newBackup.description')}
            </p>
            <Typography.Text type="warning">
              {t('newBackup.fileNameHint')}
            </Typography.Text>
          </>
        }
      >
        <Row>
          <Col flex="auto">
            <Input
              placeholder={t('newBackup.backupNamePlaceholder')}
              suffix={fieldErrorSuffix(value, valid)}
              value={value}
              disabled={loadState.loading || isBusy}
              onChange={e => {
                const { value } = e.target;
                const valid = value.length === 0 || validateFileName(value);
                setFileNameState({ valid, value });
              }}
            />
          </Col>
          <Button
            style={{ marginLeft: '5px' }}
            disabled={loadState.loading || isBusy || !valid}
            onClick={createBackup}
          >
            {t('actions.createBackup')}
          </Button>
        </Row>
      </SettingsSection>
      <ImportBackupSection
        disabled={loadState.loading}
        onChange={refreshBackupsList}
      />
      <SettingsSection
        label={t('restore.label')}
        orientation="vertical"
      >
        {loadState.error ? (
          <Typography.Text type="danger">
            Error: {loadState.error}
          </Typography.Text>
        ) : (
          <BackupsList
            loading={loadState.loading}
            disabled={isBusy}
            items={files}
            onItemDelete={onItemDelete}
            onItemSelect={onItemRestore}
          />
        )}
      </SettingsSection>
    </>
  )
};

export default BackupsPage;

