import { RPCClient } from '../rpc';
import { OK } from '../requests';
import {
  ConfigSaveResult,
  Configuration,
  ConfigurationDelta, ServerConfig
} from './types';

const SERVICE_NAME = 'SettingsService';

/**
 * SettingsService controls Hub settings that can be changed in runtime.
 * Most of settings are related to monitoring behavior.
 */
export default class SettingsService {
  constructor(private client: RPCClient) {}

  /**
   * Returns current configuration.
   */
  getSettings() {
    return this.client.callWithResult<Configuration>(SERVICE_NAME, 'GetSettings', null);
  }

  /**
   * Update current configuration using provided delta.
   *
   * @param delta configuration changes
   * @see Configuration
   */
  updateSettings(delta: ConfigurationDelta) {
    return this.client.callWithResult<OK, ConfigurationDelta>(SERVICE_NAME, 'UpdateSettings', delta);
  }


  getConfig() {
    return this.client.callWithResult<ServerConfig>(SERVICE_NAME, 'GetConfig', null);
  }

  saveConfig(cfg: ServerConfig) {
    return this.client.callWithResult<ConfigSaveResult, ServerConfig>(SERVICE_NAME, 'SaveConfig', cfg);
  }

}
