import React from 'react';
import "./AboutHubPage.css";

import {
  Typography,
  Result,
  Descriptions,
  Space,
  Skeleton,
  Button
} from "antd";
import {FileTextOutlined} from "@ant-design/icons";
import {withTranslation} from "react-i18next";
import {TFunction} from "i18next";
import LoadComponent, {LoadState} from "../../core/LoadComponent";
import {GetInfoResponse} from "../../../hub/requests";
import {hasError, hubService} from "../../../hub";

const { Item } = Descriptions;

const decorateOsName = (osName?: string) => (
  osName?.toLowerCase() === 'arch linux' ? (
    <>
      <span title="btw I use arch">{osName} &#x2764;️</span>
    </>
  ) : osName
)

class AboutHubPage extends LoadComponent<GetInfoResponse, LoadState<GetInfoResponse>, { t: TFunction }> {
  state: LoadState<GetInfoResponse> = {
    loading: true
  };

  componentDidMount() {
    this.loadData()
  }

  loadData() {
    hubService.getInfo()
      .then(rsp => {
        if (hasError(rsp)) {
          return Promise.reject(rsp.error)
        }
        this.setDataLoaded(rsp.result);
      })
      .catch(err => this.setLoadError(err))
  }

  render() {
    const { t } = this.props;
    const {data} = this.state;
    return (
      <Space
        className="AboutHubPage"
        direction="vertical"
        size="large"
      >
        { this.loadSuccess ? (
          <>
            <Descriptions
              title={t('productInfoSection')}
              column={1}
              size="small"
            >
              <Item label={t('sections.version')}>
                <span className="text-monospace">{data?.build.version}</span>
              </Item>
              <Item label={t('sections.buildNumber')}>
                <span className="text-monospace">{data?.build.build}</span>
              </Item>
              <Item label={t('sections.releaseType')}>
                <span className="text-monospace">{data?.build.type}</span>
              </Item>
              <Item label={t('sections.rigId')}>
                <span className="text-monospace">{data?.rigId}</span>
              </Item>
            </Descriptions>

            <Descriptions
              title={t('serverInfoSection')}
              column={1}
              size="small"
            >
              <Item label={t('sections.monitorStatus')}>
                {data?.monitoringActive ?
                  <Typography.Text className="text-success">{t('monitorState.running')}</Typography.Text> :
                  <Typography.Text type="warning">{t('monitorState.notRunning')}</Typography.Text>
                }
              </Item>
              <Item label={t('sections.installDir')}>
                <Typography.Text underline className="text-monospace">
                  {data?.build.installDir}
                </Typography.Text>
              </Item>
              <Item label={t('sections.os')} className="text-capitalize">
                <span className="text-monospace">{decorateOsName(data?.build.os)}</span>
              </Item>
              <Item label={t('sections.arch')}>
                <span className="text-monospace">{data?.build.cpuArch}</span>
              </Item>
              <Item label={t('sections.platform')}>
                <span className="text-monospace">{data?.build.platformName}</span>
              </Item>
            </Descriptions>
            <Button
              type="default"
              href={hubService.logFileUrl}
              icon={<FileTextOutlined />}
              target="_blank"
            >
              {t('actions.downloadLog')}
            </Button>
          </>) : null }
        { this.isLoading ? (
          <div className="content-inner">
            <Skeleton active paragraph={{ rows: 10 }}/>
          </div>
        ) : null}
        { this.loadFailed ? (
          <Result
            status="error"
            title={t('labels.errorTitle')}
            subTitle={this.loadError}
            extra={
              <Button
                type="primary"
                onClick={() => this.loadData()}
              >
                {t('actions.retry')}
              </Button>
            }
          />
        ) : null}
      </Space>
    )
  }
}

export default withTranslation('aboutPage')(AboutHubPage);
