import React from 'react';
import {Button, Empty, message, Modal, Typography} from 'antd';
import { withTranslation } from 'react-i18next';
import {
  DEFAULT_HIVE_URL,
  DeviceKey,
  DeviceQuery,
  devicesService,
  DeviceSummary,
  hubService,
  sortEqual,
  SortOrder,
} from '../../hub';

import DeviceAddModal from '../modals/DeviceAddModal';
import {DevicesList, ViewChangeEvent} from "../lists/DevicesList";
import EditDeviceModal from "../modals/EditDeviceModal";
import HubPage from "../core/HubPage";
import SearchByInput, {SearchQuery} from "../form/SearchByInput";

const {Text} = Typography;
const DEFAULT_PAGE_SIZE = 50;
const DEFAULT_PAGE = 1;
const EMPTY_SELECTION = [];

const deviceFilterOptions = {
  'workerName': 'filterLabels.workerName',
  'type': 'filterLabels.asicType',
  'ip': 'filterLabels.ip',
  'mac': 'filterLabels.mac',
  'rigId': 'filterLabels.workerId'
}

interface State {
  ready: boolean,
  devices: DeviceSummary[],
  isLoading: boolean,
  error: any,
  showDeviceAdd: boolean,
  hiveWebUrl: string,
  offlineIds?: Set<number>,
  selectedIds: number[]
  editor: {
    visible: boolean
    device?: DeviceSummary
  },
  pagination: {
    currentPage: number,
    pageSize: number,
    totalItems: number,
  },
  sorting?: {
    key: DeviceKey
    order: SortOrder
  } | null,
  search?: SearchQuery | null
}

const getOffset = (pageSize, currentPage) => {
  if (currentPage === DEFAULT_PAGE) return 0;
  return (currentPage - 1) * pageSize;
}

class DevicesPage extends React.Component<any, State> {
  public state: State = {
    ready: false,
    devices: [],
    isLoading: true,
    error: null,
    showDeviceAdd: false,
    editor: {visible: false},
    hiveWebUrl: DEFAULT_HIVE_URL,
    selectedIds: EMPTY_SELECTION,
    pagination: {
      currentPage: DEFAULT_PAGE,
      pageSize: DEFAULT_PAGE_SIZE,
      totalItems: 0,
    }
  };

  async retry() {
    if (!this.state.ready) return this.initPage();
    const {sorting, pagination} = this.state;
    const {pageSize, currentPage} = this.state.pagination;
    const offset = getOffset(pageSize, currentPage);
    await this.getDevices({limit: pagination.pageSize, offset, sorting});
  }

  async componentDidMount() {
    await this.initPage();
  }

  async initPage() {
    try {
      const {pagination} = this.state;
      let newState: any = {
        error: null,
      };

      const {count} = await devicesService.getDevicesCount();
      newState.pagination = {
        ...pagination,
        totalItems: count,
      };

      try {
        const {hiveWebUrl} = await hubService.getUrlConfig();
        newState.hiveWebUrl = hiveWebUrl;
      } catch (ex) {
        console.error('Failed to get url config, using fallback value. Error:', ex);
      }

      this.setState(newState);
      await this.getDevices({
        limit: DEFAULT_PAGE_SIZE,
        offset: 0,
      }, true);
    } catch (err) {
      this.setState({error: err.message});
    }
  }

  onBulkDelete = () => {
    const { t } = this.props;
    const {selectedIds} = this.state;
    const count = selectedIds.length;
    Modal.confirm({
      title: t('bulkRemoveModal.title', {count }),
      content: t('bulkRemoveModal.subTitle', { count }),
      okButtonProps: {
        danger: true
      },
      cancelButtonProps: {
        type: 'text'
      },
      onOk: async () => {
        this.setState({isLoading: true});
        try {
          await devicesService.removeDevices(selectedIds);
          message.success(t('bulkRemoveModal.success', {count}));
          this.refresh();
        } catch (ex) {
          this.setState({isLoading: false});
          Modal.error({
            title: t('bulkRemoveModal.failed', {count}),
            content: ex.message,
          });
        }
      }
    })
  }

  onItemDelete = (item: DeviceSummary) => {
    const { t } = this.props;
    Modal.confirm({
      title: t('itemRemoveModal.title', item),
      content: t('itemRemoveModal.subTitle'),
      okButtonProps: {
        danger: true
      },
      cancelButtonProps: {
        type: 'text'
      },
      onOk: async () => {
        this.setState({isLoading: true});
        try {
          await devicesService.removeDevice(item.id);
          message.success(t('itemRemoveModal.successMessage', item));
          this.refresh();
        } catch (ex) {
          Modal.error({
            title: t('itemRemoveModal.errorMessage', item),
            content: ex.message,
          });
        } finally {
          this.setState({isLoading: false});
        }
      }
    })
  }

  refresh = () => {
    const {pagination, sorting, search} = this.state;
    this.getDevices({
      limit: pagination.pageSize,
      offset: 0,
      sorting,
      search
    }, true);
    this.setState({
      pagination: {...pagination, currentPage: DEFAULT_PAGE}
    });
  }

  async getDevices(q: DeviceQuery, hardReload = false) {
    let {offlineIds, pagination} = this.state;
    this.setState({isLoading: true});
    try {
      const {devices} = await devicesService.getDevicesSummary(q);

      if (hardReload) {
        try {
          const {ids} = await devicesService.getOfflineDevices();
          offlineIds = new Set(ids);
        } catch (ex) {
          const { t } = this.props;
          message.error(t('messages.offlineDevicesListError', ex));
        }

        const {count} = await devicesService.getDevicesCount(q.search);
        this.setState({
          selectedIds: EMPTY_SELECTION,
          pagination: {
            currentPage: DEFAULT_PAGE,
            pageSize: pagination.pageSize,
            totalItems: count,
          }
        });
      }

      this.setState({
        error: null,
        isLoading: false,
        devices,
        offlineIds,
      });
    } catch (err) {
      this.setState({isLoading: false, error: err.message, offlineIds});
    }
  }

  setEditorState(visible: boolean, device?: DeviceSummary) {
    this.setState({editor: {visible, device}})
  }

  onSearch = (search: SearchQuery | null) => {
    const {sorting, pagination} = this.state;
    const {pageSize} = pagination;
    this.getDevices({limit: pageSize, offset: 0, sorting, search}, true);
    this.setState({
      search, pagination: {currentPage: DEFAULT_PAGE, pageSize, totalItems: 0}
    });
  }

  onPageChange = async (p: ViewChangeEvent) => {
    const {search} = this.state;
    const {totalItems} = this.state.pagination;
    const {offset, pageSize, currentPage, sorting} = p;

    if (sortEqual(this.state.sorting, sorting)) {
      // just change page if sort didn't change
      const pagination = {totalItems, offset, pageSize, currentPage};
      this.setState({pagination, sorting});
      await this.getDevices({limit: pageSize, offset, sorting, search});
      return;
    }

    // Move to a first page when sorting changed
    this.setState({
      selectedIds: EMPTY_SELECTION,
      pagination: {
        totalItems,
        pageSize,
        currentPage: DEFAULT_PAGE
      }, sorting
    });
    await this.getDevices({limit: pageSize, offset: 0, sorting, search});
  }

  render() {
    const { t } = this.props;
    const {
      isLoading,
      error,
      devices,
      editor,
      showDeviceAdd,
      offlineIds,
      search,
      selectedIds
    } = this.state;
    return (
      <HubPage
        title={t('pageTitle')}
        subTitle={t('subTitle')}
        extra={[
          <Button
            key="1"
            danger
            hidden={!selectedIds.length}
            onClick={() => this.onBulkDelete()}
          >
            {t('actions.deleteDevice', {count: selectedIds.length})}
          </Button>,
          <Button
            key="2"
            type="default"
            onClick={() => this.setState({showDeviceAdd: true})}
          >
            {t('actions.openDeviceAddModal')}
          </Button>,
        ]}
      >
        <SearchByInput
          options={deviceFilterOptions}
          i18nNamespace={'devicesPage'}
          disabled={isLoading}
          value={search}
          onValueChange={search => this.onSearch(search)}
          placeholderFormat={key => `searchCriteriaLabels.${key}`}
        />
        <DevicesList
          loading={isLoading}
          devices={devices}
          error={error}
          offlineIds={offlineIds}
          selectedIds={selectedIds}
          locale={{
            emptyText: (
              // Display "no devices to monitor" only if no search performed.
              search ? null :
                <Empty
                  image={Empty.PRESENTED_IMAGE_SIMPLE}
                  description={<Text>{t('noDevicesLabel')}</Text>}
                >
                  <Button
                    type="primary"
                    onClick={() => this.setState({showDeviceAdd: true})}
                  >
                    {t('actions.openDeviceAddModal')}
                  </Button>
                </Empty>
            )
          }}
          onRetry={() => this.retry()}
          onRemove={i => this.onItemDelete(i)}
          onChange={(p) => this.onPageChange(p)}
          onEdit={d => this.setEditorState(true, d)}
          onSelect={selectedIds => this.setState({selectedIds})}
          {...this.state.pagination}
        />
        {showDeviceAdd && <DeviceAddModal
          visible={showDeviceAdd}
          onSuccess={(count) => {
            message.success(t('messages.deviceAdded', {count}));
            this.setState({showDeviceAdd: false})
            this.refresh();
          }}
          onCancel={() => this.setState({showDeviceAdd: false})}
        />}
        <EditDeviceModal
          visible={editor.visible}
          device={editor.device}
          onCancel={() => this.setEditorState(false)}
          onResult={err => {
            const {ip, type} = editor.device as DeviceSummary;
            this.setEditorState(false);
            if (err) {
              message.error(t('messages.deviceUpdateFailed', {ip, err: err.message ?? err}), 5);
              return;
            }

            message.success(t('messages.deviceUpdateSuccess', { ip, type }));
            this.refresh();
          }}
        />
      </HubPage>
    );
  }
}

export default withTranslation('devicesPage')(DevicesPage);
