import React from 'react';
import {
  DownloadProgress,
  EventType
} from "../../hub/update/types";
import {Modal, Progress, Space, Typography} from "antd";
import {hasError, updateService} from "../../hub";
import {withTranslation} from "react-i18next";
import {TFunction} from "i18next";

const SECOND = 1000;
const progressCheckIntervalMs = 300;
const rebootIntervalSec = 30;

interface UpdateProgressModalProps {
  t: TFunction
  visible?: boolean
  onSuccess: () => void
  onError: (err) => void
}

const defaultState = {
  currentEvent: EventType.Idle,
  percentage: 0,
  trackStarted: false,
  error: null as any,
  timeoutCountdown: 0,
}

class UpdateProgressModal extends React.Component<UpdateProgressModalProps> {
  state = defaultState

  get progressLabel() {
    const { t } = this.props;
    const { error, currentEvent } = this.state;
    switch (currentEvent) {
      case EventType.Idle:
        return t('installStage.preparation')
      case EventType.Download:
        return t('installStage.downloading')
      case EventType.Install:
        return t('installStage.installing')
      case EventType.Reboot:
        return t('installStage.reboot')
      case EventType.Error:
        return t('installStage.error', {
          message: error.message ?? error.toString()
        });
      default:
        return '';
    }
  }

  rebootIntervalTick() {
    let {timeoutCountdown} = this.state;
    if (timeoutCountdown >= rebootIntervalSec) {
      this.setState(defaultState);
      this.props.onSuccess();
      return;
    }

    const percentage = (timeoutCountdown * 100) / rebootIntervalSec;
    timeoutCountdown++;
    this.setState({currentEvent: EventType.Reboot, percentage, timeoutCountdown});
    setTimeout(() => this.rebootIntervalTick(), SECOND);
  }

  getProgressUpdate() {
    if (!this.props.visible) {
      return;
    }

    if (!this.state.trackStarted) {
      this.setState({trackStarted: true});
    }

    updateService.getUpgradeProgress().then(rsp => {
      if (hasError(rsp)) {
        return Promise.reject(rsp.error)
      }

      const {type, message, data} = rsp.result;
      let newState: any = {currentEvent: type};
      switch (type) {
        case EventType.Download:
          const {totalBytes, downloadedBytes} = data as DownloadProgress;
          newState.percentage = (downloadedBytes * 100) / totalBytes;
          break;
        case EventType.Reboot:
          newState.percentage = 0;
          this.rebootIntervalTick();
          break;
        case EventType.Install:
          newState.percentage = 100;
          break;
        case EventType.Error:
          // exit on error
          return Promise.reject({message});
        default:
          break;
      }

      this.setState(newState);
      if (type !== EventType.Reboot) {
        setTimeout(() => this.getProgressUpdate(), progressCheckIntervalMs);
      }

    }).catch(err => {
      this.setState(defaultState);
      this.props.onError(err);
    })
  }

  componentDidUpdate(prevProps: Readonly<UpdateProgressModalProps>) {
    const { visible } = this.props;
    const {trackStarted} = this.state;
    if (!visible) {
      // do nothing if modal is hidden
      return;
    }

    if (trackStarted) {
      // do nothing if already tracking update progress
      return;
    }

    // reset modal and start tracking progress
    this.setState(defaultState);
    this.getProgressUpdate();
  }

  render() {
    const { visible, t } = this.props;
    return (
      <Modal
        title={t('newUpdates.updateInstallModalTitle')}
        visible={visible}
        centered={true}
        closable={false}
        maskClosable={false}
        footer={null}
      >
        <Space direction="vertical" style={{width: '100%'}}>
          <Typography.Text>{this.progressLabel}</Typography.Text>
          <Progress
            percent={this.state.percentage}
            status="active"
            format={p => `${p?.toFixed(1) || 0}%`}
            showInfo
          />
        </Space>
      </Modal>
    )
  }
}

export default withTranslation('softwareUpdate')(UpdateProgressModal);
