import React from 'react';
import {Fields, LogRecord} from "../../../hub/log";
import {Typography} from "antd";
import './LogEntryDetails.less';

interface LogEntryDetailsProps {
  record: LogRecord
  visible: boolean
}

const objectToKeyValue = (obj: Fields) =>
  Object.entries(obj).map(([key, value]) => ({key, value: formatObjectValue(value)}));

const formatObjectValue = val => typeof val === 'object' ? JSON.stringify(val) : val;

const LogEntryDetails: React.FC<LogEntryDetailsProps> = ({record, visible}) => {
  const {message, error, fields, level} = record;
  return (
    <div
      className="LogEntryDetails"
      style={{
        'display': visible ? 'block' : 'none'
      }}
    >
      <div className="LogEntryDetails__info">
        <p className="text-monospace">
          {message}
        </p>
        {error ? (
          <p>
            <b>
              <Typography.Text type="danger" className="text-monospace">
                {error}
              </Typography.Text>
            </b>
          </p>
        ) : null}
      </div>
      <div className="LogEntryDetails__fields">
        <div className="LogEntryDetails__field" key="level">
          <b>level:</b><span className="text-monospace">{level}</span>
        </div>

        {
          (fields && Object.keys(fields).length) ? objectToKeyValue(fields).map(({key, value}) => (
            <div className="LogEntryDetails__field" key={key}>
              <b>{key}:</b><span className="text-monospace">{value}</span>
            </div>
          )) : null
        }
      </div>
    </div>
  );
}

export default LogEntryDetails;
