import { Store } from 'redux';
import { configureStore } from '@reduxjs/toolkit';
import { persistStore, PersistConfig, Persistor, persistReducer } from 'redux-persist';
import storage from 'redux-persist/lib/storage';
import { i18n } from "i18next";
import {State} from "./state";
import {Action} from "./actions";
import {createRootReducer, getInitialState} from "./reducers";
import {isDevelopment} from "../env";

const persistConfig: PersistConfig<State> = {
  key: 'state',
  storage: storage,
  whitelist: ['language']
};

/**
 * Returns a new Redux store and persistor
 * @param i18nInstance i18next instance
 */
export const createStore = ({i18nInstance} : { i18nInstance: i18n }): [Store<State, Action>, Persistor] => {
  const persistedReducer = persistReducer(persistConfig, createRootReducer());

  const store = configureStore({
    devTools: isDevelopment(),
    preloadedState: getInitialState(),
    reducer: persistedReducer,
    middleware: getDefaultMiddleware =>
      getDefaultMiddleware({
        thunk: {
          extraArgument: {
            i18nInstance
          },
        },
        serializableCheck: {
          // See: https://github.com/rt2zz/redux-persist/issues/988
          ignoredActions: ['persist/PERSIST']
        }
      })
  });

  const persistor = persistStore(store);
  return [store, persistor];
};
