import { RPCClient } from '../rpc';
import { DeviceRegistration } from '../requests';
import {
  OK,
  IDs,
  Pagination,
  DevicesListResponse,
  DevicesCountResponse,
} from '../requests';
import {
  AddDevicesResponse,
  DeviceInfoChanges,
  DeviceQuery,
  DeviceSearchQuery,
  DeviceSummary
} from "./types";

const SERVICE_NAME = 'DevicesService'

export default class DevicesService {
  constructor(private client: RPCClient) {}

  getDeviceByIp(ip: string) {
    return this.client.call<DeviceSummary>(SERVICE_NAME, 'GetDeviceByIP', {ip});
  }

  getDevicesCount(searchQuery?: DeviceSearchQuery | null) {
    return this.client.callWithResult<DevicesCountResponse>(SERVICE_NAME, 'GetDevicesCount', searchQuery);
  }

  addDevices(devices: DeviceRegistration[], noRestart=false) {
    return this.client.callWithResult<AddDevicesResponse>(SERVICE_NAME, 'AddDevices', {devices, noRestart});
  }

  updateDeviceById(id: number, changes: DeviceInfoChanges) {
    return this.client.call<OK>(SERVICE_NAME, 'UpdateDeviceByID', {id, changes});
  }

  updateDeviceByIp(ip: string, changes: DeviceInfoChanges) {
    return this.client.call<OK>(SERVICE_NAME, 'UpdateDeviceByIP', {ip, changes});
  }

  removeDeviceByIp(ip: string) {
    return this.client.callWithResult<OK>(SERVICE_NAME, 'RemoveDeviceByIP', {ip});
  }

  removeDevice(id: number) {
    return this.removeDevices([id])
  }

  removeDevices(ids: number[]) {
    return this.client.callWithResult<OK>(SERVICE_NAME, 'RemoveDevices', {ids});
  }

  getDevicesSummary(query: DeviceQuery) {
    return this.client.callWithResult<DevicesListResponse, Pagination>(SERVICE_NAME, 'GetDevicesSummary', query);
  }

  getOfflineDevices() {
    return this.client.callWithResult<IDs>(SERVICE_NAME, 'GetOfflineDevices', null);
  }
}

