import React, { useEffect, useState } from "react";
import Timeline from "antd/lib/timeline";
import ReactMarkdown from "react-markdown";
import { updateService } from "../../../hub";
import { ChangeLog } from "../../../hub/update/types";
import "./ChangeLog.css";


const ChangleLogList: React.FC = () => {
  const [changeLogList, setChangeLogList] = useState<ChangeLog[]>([])

  useEffect(() => {
    updateService.getChangeLogList().then(res => {
      setChangeLogList(res.data);
    })
  }, []);

  return (
    <>
      <Timeline mode='left' className="changeLog">
        {changeLogList.map((el, i) => (
          <Timeline.Item key={i} color='#fa7a03' label={el.date} >
            <h2>{el.version}</h2>
            <ReactMarkdown>{el.description}</ReactMarkdown>
          </Timeline.Item>
        ))}
      </Timeline>
    </>
  )
};

export default ChangleLogList;